  const clickStartRef = useRef({ x: 0, y: 0 });

  const flagUrl = useMemo(() => generateChinaFlagTexture(), []);
  const flagTexture = useMemo(() => new TextureLoader().load(flagUrl), [flagUrl]);

  useFrame((state, delta) => {
    if (stationRef.current && !isPaused) {
       // Orbit rotation
       stationRef.current.rotation.y += delta * 0.5 * simulationSpeed;
    }

    // Solar panels sun-tracking animation (Simple rotation)
    if (labPanelsRef.current && !isPaused) {
       labPanelsRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.2) * 0.2; 
    }

    // Breathing Light Effect for Selection
    if (materialRef.current) {
        if (isSelected || hovered) {
            const t = state.clock.elapsedTime;
            materialRef.current.emissive.set(TIANGONG_DATA.color);
            materialRef.current.emissiveIntensity = 0.2 + (Math.sin(t * 3) + 1) * 0.15; 
        } else {
