  useFrame((state, delta) => {
    // Orbital rotation around Earth (handled by parent group usually, but here we add local spin for view)
    if (stationRef.current && !isPaused) {
       // Slow tumble or maintaining orientation - let's keep it mostly stable relative to earth surface usually
       // but for visualization we rotate it slowly to show off the model
       stationRef.current.rotation.y += delta * 0.2 * simulationSpeed;
    }

    // Solar panels tracking sun (simplified animation)
    if (solarArraysRef.current && !isPaused) {
       solarArraysRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.3) * 0.2; 
    }

    // Selection Highlight
