export const Planet: React.FC<PlanetProps> = ({ 
  data, 
  isSelected, 
  onSelect, 
  isPaused,
  simulationSpeed,
  earthPositionRef,
  planetRefs,
  isStarshipActive,
  showOrbit
}) => {
  const meshRef = useRef<Mesh>(null);
  const orbitGroupRef = useRef<Group>(null);
  const inclinationGroupRef = useRef<Group>(null); 
  const materialRef = useRef<MeshPhysicalMaterial>(null);
  const [hovered, setHovered] = useState(false);
  const clickStartRef = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (orbitGroupRef.current) {
      planetRefs.current[data.id] = orbitGroupRef.current;
    }
  }, [data.id, planetRefs]);

  const orbitAngleRef = useRef(Math.random() * Math.PI * 2);

  const textureUrl = useMemo(() => generatePlanetTexture(data), [data]);
  const texture = useMemo(() => new TextureLoader().load(textureUrl), [textureUrl]);

  const ringTextureUrl = useMemo(() => data.hasRings && data.ringColor ? generateRingTexture(data.id, data.ringColor) : null, [data]);
  const ringTexture = useMemo(() => ringTextureUrl ? new TextureLoader().load(ringTextureUrl) : null, [ringTextureUrl]);

  const glowTextureUrl = useMemo(() => data.atmosphereColor ? generateGenericGlowTexture() : null, [data.atmosphereColor]);
  const glowTexture = useMemo(() => glowTextureUrl ? new TextureLoader().load(glowTextureUrl) : null, [glowTextureUrl]);

  useFrame((state, delta) => {
    if (!orbitGroupRef.current || !meshRef.current) return;

    if (!isPaused) {
      orbitAngleRef.current += delta * data.speed * 0.1 * simulationSpeed;

      const x = Math.cos(orbitAngleRef.current) * data.distance;
      const z = -Math.sin(orbitAngleRef.current) * data.distance;

      orbitGroupRef.current.position.set(x, 0, z);
      meshRef.current.rotation.y += data.rotationSpeed * simulationSpeed;

      if (data.id === 'earth') {
        orbitGroupRef.current.getWorldPosition(earthPositionRef.current);
      }
    }

    // Breathing Light Effect
    if (materialRef.current) {
        if (isSelected || hovered) {
            const t = state.clock.elapsedTime;
            materialRef.current.emissive.set(data.color);
            // Range: 0.05 to 0.2 (averaging around ~0.125, slightly dynamic)
            materialRef.current.emissiveIntensity = 0.05 + (Math.sin(t * 2.5) + 1) * 0.075; 
        } else {
            materialRef.current.emissiveIntensity = 0;
            materialRef.current.emissive.setHex(0x000000);
        }
    }
  });

  return (
    <group ref={inclinationGroupRef} rotation={[0, 0, data.orbitInclination || 0]}>

      <mesh rotation={[-Math.PI / 2, 0, 0]} visible={!isStarshipActive && showOrbit}>
        <ringGeometry args={[data.distance - 0.05, data.distance + 0.05, 128]} />
        <meshBasicMaterial color="#ffffff" opacity={0.35} transparent side={DoubleSide} />
      </mesh>

      <group ref={orbitGroupRef}>
        <group rotation={[0, 0, data.axisTilt || 0]}>
          <mesh
            ref={meshRef}
            onPointerDown={(e) => { e.stopPropagation(); clickStartRef.current = { x: e.clientX, y: e.clientY }; }}
            onClick={(e) => {
              e.stopPropagation();
              const dx = e.clientX - clickStartRef.current.x;
              const dy = e.clientY - clickStartRef.current.y;
              if (Math.sqrt(dx * dx + dy * dy) < 5) onSelect(data.id);
            }}
            onPointerOver={() => { document.body.style.cursor = 'pointer'; setHovered(true); }}
            onPointerOut={() => { document.body.style.cursor = 'auto'; setHovered(false); }}
          >
            <sphereGeometry args={[data.size, 64, 64]} />
            <meshPhysicalMaterial 
              ref={materialRef}
              map={texture}
              color="#ffffff" 
              roughness={0.6}
              metalness={0.2}
              clearcoat={0.3}
            />

            {/* New Upward Growing Label */}
            {hovered && (
              <Html position={[0, data.size * 1.1, 0]} zIndexRange={[100, 0]} style={{ pointerEvents: 'none' }}>
                 <TechLabel name={data.name} color={data.color} />
              </Html>
            )}
          </mesh>

          {data.hasRings && ringTexture && (
            <mesh rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[data.size * 1.4, data.size * 2.3, 128]} />
              <meshStandardMaterial 
                map={ringTexture}
                color="#ffffff" 
                opacity={0.9} 
                transparent 
                side={DoubleSide} 
                roughness={0.4}
                metalness={0.2}
              />
            </mesh>
          )}
        </group>

        {data.id === 'earth' && (
          <>
            <Moon isPaused={isPaused} simulationSpeed={simulationSpeed} showOrbit={showOrbit} onSelect={onSelect} isSelected={isSelected} />
            <TiangongStation isPaused={isPaused} simulationSpeed={simulationSpeed} showOrbit={showOrbit} onSelect={onSelect} isSelected={isSelected} />
          </>
        )}

        {data.id === 'jupiter' && <JupiterMoons isPaused={isPaused} simulationSpeed={simulationSpeed} onSelect={onSelect} selectedId={isSelected ? data.id : null} showOrbit={showOrbit} />}
        {data.id === 'saturn' && <SaturnMoons isPaused={isPaused} simulationSpeed={simulationSpeed} onSelect={onSelect} selectedId={isSelected ? data.id : null} showOrbit={showOrbit} />}

        {data.atmosphereColor && glowTexture && (
           <Billboard>
              <mesh scale={[data.size * 2.8, data.size * 2.8, 1]} raycast={() => null}>
                <planeGeometry args={[1, 1]} />
                <meshBasicMaterial 
                  map={glowTexture} 
                  transparent 
                  opacity={0.25}
                  depthWrite={false}
                  blending={AdditiveBlending}
                  color={new Color(data.atmosphereColor)}
                />
              </mesh>
           </Billboard>
        )}

      </group>
    </group>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh, Matrix4 } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine
type ShipState = 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // Refs for loop variables to avoid re-renders
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // --- PHYSICS & MOVEMENT REFS ---
  const velocityRef = useRef(new Vector3(0, 0, 0)); // The actual movement vector
  const speedRef = useRef(0); // Scalar speed
  const targetBankingRef = useRef(0); // Target Z-rotation
  const currentBankingRef = useRef(0); // Smoothed Z-rotation

  // Orbiting specific refs
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const orbitCenterRef = useRef(new Vector3());
  const totalOrbitTraveledRef = useRef(0);

  // Camera smoothing
  const camDistRef = useRef(16); 

  // Constants
  const MAX_SPEED = 28; 
  const ORBIT_SPEED = 10; 
  const TURN_SPEED = 2.0; // Radians per second, lower = smoother turns
  const BANK_FACTOR = 3.0; // How much to roll when turning

  // Helper to generate mission route
  const generateMission = () => {
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; 

     // Pick 4 random planets (Reduced from 5 for better pacing)
     for (let i = 0; i < 4; i++) {
        let next: string;
        let attempts = 0;
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);

        mission.push(next);
        lastPlanet = next;
     }

     mission.push('earth');
     return mission;
  };

  // Helper to calculate a safe but close orbit radius for each planet
  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; 
     if (p.hasRings) return p.size * 2.5 + 4.0; 
     return p.size * 2.8 + 3.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const pos = groupRef.current.position;

    // --- 0. INITIALIZATION: Spawn at Earth ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { 
             startPos.y += 5.0; 
             startPos.x += 15.0; 
             groupRef.current.position.copy(startPos);

             // Initialize velocity tangent to earth roughly
             velocityRef.current.set(0, 0, 1).normalize();

             // Orient ship
             const dummy = new Object3D();
             dummy.position.copy(startPos);
             dummy.lookAt(startPos.clone().add(velocityRef.current));
             groupRef.current.quaternion.copy(dummy.quaternion);

             initializedRef.current = true;
             stateRef.current = 'PLANNING';
        }
      }
      return; 
    }

    // --- 1. MISSION CONTROL ---
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();

       // Pop first target
       const nextId = missionQueueRef.current.shift()!;
       currentTargetIdRef.current = nextId;

       // Update UI
       const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
       setMissionProgress({ current: 1, total: 5, targetName: pName });

       stateRef.current = 'TRAVELING'; // Go straight to traveling, physics handles the turn
       speedRef.current = MAX_SPEED * 0.5; // Start with some speed
       return;
    }

    // Check Mission Complete
    if (stateRef.current === 'COMPLETED') {
        onMissionComplete();
        return;
    }

    // --- 2. PHYSICS ENGINE & NAVIGATION ---

    // Default: fly forward
    let targetDirection = velocityRef.current.clone().normalize();
    let targetSpeed = MAX_SPEED;
    let isOrbiting = false;

    // Target Logic
    let targetObj: Object3D | null = null;
    let targetWorldPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetWorldPos);
    }

    // === STATE: TRAVELING ===
    if (stateRef.current === 'TRAVELING' && targetObj) {
       // Aim for a point slightly "outside" the planet to enter orbit gracefully
       // We calculate the tangent point on the orbit radius circle
       const distToPlanet = pos.distanceTo(targetWorldPos);
       const safeRadius = getSafeOrbitRadius(tId!);

       // Vector from ship to planet center
       const toPlanet = new Vector3().subVectors(targetWorldPos, pos);

       // If we are far, aim straight for the "entry point" on the orbit ring
       // The entry point is dynamically calculated to be on the side of the planet we are approaching
       const dirToPlanet = toPlanet.clone().normalize();

       // Offset target to the side to create a tangential approach path
       // Cross product with Up gives a vector perpendicular to approach
       const tangentOffset = new Vector3(0, 1, 0).cross(dirToPlanet).normalize().multiplyScalar(safeRadius);
       const approachTarget = targetWorldPos.clone().add(tangentOffset);

       // Update Target Direction
       targetDirection = new Vector3().subVectors(approachTarget, pos).normalize();

       // Arrival Logic
       if (distToPlanet < safeRadius + 5) {
           stateRef.current = 'ORBITING';
           orbitRadiusRef.current = safeRadius;
           orbitCenterRef.current.copy(targetWorldPos);

           // Calculate initial orbit angle based on current position relative to planet
           const relative = new Vector3().subVectors(pos, targetWorldPos);
           orbitAngleRef.current = Math.atan2(relative.z, relative.x);
           totalOrbitTraveledRef.current = 0;
       }
    }

    // === STATE: ORBITING ===
    else if (stateRef.current === 'ORBITING' && targetObj) {
       isOrbiting = true;
       targetSpeed = ORBIT_SPEED;
       orbitCenterRef.current.copy(targetWorldPos); // Keep updating center as planet moves

       // Calculate ideal orbital position (next frame)
       // Orbit direction: Counter-Clockwise
       const nextAngle = orbitAngleRef.current + (targetSpeed / orbitRadiusRef.current) * delta;

       const idealX = orbitCenterRef.current.x + Math.cos(nextAngle) * orbitRadiusRef.current;
       const idealZ = orbitCenterRef.current.z + Math.sin(nextAngle) * orbitRadiusRef.current;
       const idealY = orbitCenterRef.current.y;
       const idealPos = new Vector3(idealX, idealY, idealZ);

       // Our target direction is simply towards that ideal position
       targetDirection = new Vector3().subVectors(idealPos, pos).normalize();

       // Manually advance orbit logic tracker
       const angleDiff = (targetSpeed / orbitRadiusRef.current) * delta;
       orbitAngleRef.current += angleDiff;
       totalOrbitTraveledRef.current += angleDiff;

       // Exit Orbit Condition
       if (totalOrbitTraveledRef.current > Math.PI * 1.5) {
           stateRef.current = 'LEAVING';
       }
    }

    // === STATE: LEAVING ===
    else if (stateRef.current === 'LEAVING') {
       // Fly straight tangent for a bit
       // targetDirection is kept as current velocity direction (inertia)
       targetSpeed = MAX_SPEED;

       // If we moved far enough away, pick next target
       const distFromLastTarget = targetObj ? pos.distanceTo(targetWorldPos) : 9999;

       if (distFromLastTarget > 40) {
           if (missionQueueRef.current.length > 0) {
               const nextId = missionQueueRef.current.shift()!;
               currentTargetIdRef.current = nextId;

               const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
               setMissionProgress(prev => ({ 
                   current: prev.current + 1, 
                   total: prev.total, 
                   targetName: pName
               }));

               stateRef.current = 'TRAVELING';
           } else {
               stateRef.current = 'COMPLETED';
           }
       }
    }

    // --- 3. APPLY SMOOTH STEERING ---

    // A. Smooth Speed Change
    speedRef.current = MathUtils.lerp(speedRef.current, targetSpeed, delta * 1.0);

    // B. Smooth Rotation (Steering)
    // We want the current velocity vector to slowly rotate towards targetDirection
    // Slerping vectors directly
    const currentDirNormalized = velocityRef.current.clone().normalize();
    // Clamp the turn angle to prevent jitter if angle is huge (though vector lerp handles this well)
    // Use a 'heavy' lerp for momentum feel
    const smoothedDir = new Vector3().lerpVectors(currentDirNormalized, targetDirection, TURN_SPEED * delta).normalize();

    // Update actual Velocity
    velocityRef.current = smoothedDir.multiplyScalar(speedRef.current);

    // Update Position
    const moveStep = velocityRef.current.clone().multiplyScalar(delta);
    groupRef.current.position.add(moveStep);

    // Update Ship Orientation (Face where we are going)
    // We use a dummy object to calculate the LookAt quaternion, then slerp the ship towards it
    const dummyObj = new Object3D();
    dummyObj.position.copy(pos);
    dummyObj.lookAt(pos.clone().add(smoothedDir));

    // Slerp the ship mesh to face velocity
    groupRef.current.quaternion.slerp(dummyObj.quaternion, 4.0 * delta); // High value here means nose follows velocity quickly


    // --- 4. DYNAMIC BANKING (ROLL) ---
    // Calculate how hard we are turning
    // Cross product of Current Direction and Target Direction gives axis of rotation
    // The Y component of that cross product tells us if we are turning Left or Right
    const crossY = new Vector3().crossVectors(currentDirNormalized, targetDirection).y;

    // If crossY > 0, we are turning Left -> Bank Left (Positive Z rotation)
    // Note: In ThreeJS, usually Z rotation + is CCW.
    // Let's visualize: 
    // Ship forward (0,0,1). Target (1,0,1) -> Turn Right. 
    // Right turn = Bank Right = Negative Z rotation.
    // Cross(Forward, Target) -> (0,0,1) x (1,0,1) = (0, 1, 0). Y is Positive.
    // So Positive Y cross = Turn Right ?? No.
    // Forward (0,0,1) x Right (1,0,0) = (0,1,0). 
    // Actually, let's just use a signed angle logic relative to ship Up

    // Simpler banking logic:
    // Determine the "Yaw" delta. 
    // We can infer desired bank from the cross product magnitude and direction relative to ship up.

    // Target bank angle is proportional to the turn sharpness
    let desiredBank = 0;

    // Only bank if we are moving
    if (speedRef.current > 1) {
        // Use the cross product of Velocity vs Desired Direction
        // Transform target direction into local space to see if it's left or right
        const localTarget = targetDirection.clone().applyQuaternion(groupRef.current.quaternion.clone().invert());

        // localTarget.x tells us horizontal deviation.
        // +x is Left (in standard threejs if looking down -z? No, let's rely on observation)
        // Usually: +x is Right.
        // If target is to the Right (+x), we want to Roll Right (Negative Z).
        desiredBank = -localTarget.x * BANK_FACTOR;
    }

    // Clamp banking
    desiredBank = MathUtils.clamp(desiredBank, -Math.PI / 3, Math.PI / 3);

    // In Orbit, force a gentle inward bank
    if (isOrbiting) {
        desiredBank = -Math.PI / 4; // Always bank left/inward for CCW orbit
    }

    // Smoothly interpolate current banking
    currentBankingRef.current = MathUtils.lerp(currentBankingRef.current, desiredBank, delta * 2.0);

    if (shipModelRef.current) {
        shipModelRef.current.rotation.z = currentBankingRef.current;
    }


    // --- 5. CAMERA & HUD UPDATES ---
    const displayVal = Math.round(speedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // Camera Chase Logic
    const targetCamDist = isOrbiting ? 30 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    // Lift camera slightly based on speed/distance
    const heightOffset = MathUtils.lerp(5, 10, (camDistRef.current - 16) / (30 - 16));

    // Place camera behind ship
    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.1);

    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(20));
