// Updated Controller with Smoothing to prevent Jitter
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  // Store smoothed values to prevent camera shaking from noisy hand data
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      // Smoothing factor: Lower = Smoother/Slower, Higher = More responsive/Jittery
      // 5.0 * delta gives a nice weighted average over ~0.2 seconds
      const smoothFactor = 5.0 * delta;

      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      // Use a small deadzone to stop movement completely when hands are steady
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      const isActive = activeDx !== 0 || activeDy !== 0;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // Hand Left/Right (dx) -> Rotate Azimuth
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);

             // Hand Up/Down (dy) -> Rotate Polar Angle
             // Requirement: "Up movement -> Camera angle moves down"
             // Hand Up (dy < 0). 'activeDy' is negative.
             // We want Camera Down -> Increase Polar Angle (towards PI/2).
             // Subtracting negative activeDy adds to the angle.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);

          } else if (gestureType === 'zoom') {
             // ZOOM MODE
             const zoomSensitivity = 0.015; // Adjusted sensitivity

             // Smooth zoom application
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);

             // activeDy corresponds to change in distance between hands (Spread > 0, Close < 0)
             // Requirement: "Hands spread and lengthen distance -> view zooms in"
             if (activeDy > 0) {
                 // Spread -> Zoom In (Dolly In)
                 controlsRef.current.dollyIn(speed);
             } else {
                 // Close -> Zoom Out (Dolly Out)
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); // AR Mode State

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  // Safety Effect: Ensure body background is black on mount, and transparent on AR
  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const toggleOrbits = () => {
    setShowOrbits(!showOrbits);
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      // If turning off gesture mode, also turn off AR
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);

    if (activating) {
       // Stop star map rotation
       setIsPaused(true);
       setSelectedPlanetId(null); // Close any open panels
       // Reset speed for stability
       setSimulationSpeed(1.0); 
    } else {
       // Resume star map
       setIsPaused(false);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setIsPaused(false); // Resume star map
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;

    // Check main planets
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    // Check Jupiter's moons
    const jMoon = JUPITER_MOONS.find(m => m.id === selectedPlanetId);
    if (jMoon) return jMoon;
    // Check Saturn's moons
    return SATURN_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
        showOrbits={showOrbits}
        toggleOrbits={toggleOrbits}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      {/* 
         Canvas needs alpha: true for transparency.
         When AR Mode is ON, we hide the Skybox and opaque layers so the video behind shows through.
         onPointerMissed handles clicking empty space to deselect/close popups.
      */}
      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          // If we clicked on empty space (not a mesh), close the info panel
          if (selectedPlanetId) {
            handleClose();
          }
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            // Slower auto-rotate for better default experience
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Always show, they look nice floating in room) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Skybox) - HIDE IN AR MODE */}
          {!isARMode && <Skybox />}

          {/* 3. Magical Dust */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
              showOrbit={showOrbits}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, Quaternion, MathUtils } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine including Countdown and Liftoff
type ShipState = 'PLANNING' | 'COUNTDOWN' | 'LIFTOFF' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });
  const [countdownText, setCountdownText] = useState<string | null>(null); // For 3, 2, 1

  // Refs for loop variables
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // --- PHYSICS REFS ---
  const velocityRef = useRef(new Vector3(0, 0, 0));
  const speedRef = useRef(0); 
  const currentBankingRef = useRef(0); 

  // Orbiting specific
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const orbitCenterRef = useRef(new Vector3());
  const totalOrbitTraveledRef = useRef(0);
  const orbitEntryTangentRef = useRef(new Vector3()); // To smooth entry

  // Camera
  const camDistRef = useRef(16); 

  // Constants
  const TRAVEL_SPEED = 20; // Reduced speed for better visibility
  const ORBIT_SPEED = 12; 
  const TURN_SPEED = 1.5; 
  const BANK_FACTOR = 3.5; 

  // Generate route: Earth -> [Mars, Jupiter, Saturn, Uranus, Neptune] -> Earth
  // Exclude: Mercury, Venus, Pluto
  const generateMission = () => {
     // Get valid outer planets
     const outerPlanets = ['mars', 'jupiter', 'saturn', 'uranus', 'neptune'];

     // Shuffle
     for (let i = outerPlanets.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [outerPlanets[i], outerPlanets[j]] = [outerPlanets[j], outerPlanets[i]];
     }

     // Add Earth at the end
     outerPlanets.push('earth');
     return outerPlanets;
  };

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 15; 
     if (p.id === 'earth') return 5.0; // Tighter orbit for Earth
     // Ensure orbit is outside rings/moons
     if (p.hasRings) return p.size * 2.5 + 4.0; 
     return p.size * 3.0 + 3.0; 
  };

  // Countdown Logic
  useEffect(() => {
     if (stateRef.current === 'PLANNING') {
         stateRef.current = 'COUNTDOWN';

         const schedule = [
             { time: 500, text: "3" },
             { time: 1500, text: "2" },
             { time: 2500, text: "1" },
             { time: 3500, text: "起飞!" },
         ];

         schedule.forEach(item => {
             setTimeout(() => setCountdownText(item.text), item.time);
         });

         setTimeout(() => {
             setCountdownText(null);
             stateRef.current = 'LIFTOFF';

             // Initialize Mission Queue
             missionQueueRef.current = generateMission();
             const nextId = missionQueueRef.current.shift()!;
             currentTargetIdRef.current = nextId;

             const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
             setMissionProgress({ current: 1, total: 6, targetName: pName }); // 5 planets + Earth return = 6 legs

         }, 4500);
     }
  }, []);

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const pos = groupRef.current.position;

    // --- 0. INITIALIZATION: Spawn at Earth Surface ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        // Spawn effectively "Landed" on top
        if (startPos.lengthSq() > 1) { 
             startPos.y += 1.5; // Just above surface
             groupRef.current.position.copy(startPos);

             // Point UP initially
             velocityRef.current.set(0, 1, 0).normalize();

             const dummy = new Object3D();
             dummy.position.copy(startPos);
             dummy.lookAt(startPos.clone().add(velocityRef.current));
             groupRef.current.quaternion.copy(dummy.quaternion);

             initializedRef.current = true;
        }
      }
      return;
    }

    if (stateRef.current === 'COUNTDOWN') {
        // Just hover slightly or rumble
        groupRef.current.position.y += Math.sin(state.clock.elapsedTime * 20) * 0.005;
        return;
    }

    // --- 2. PHYSICS ENGINE ---

    let targetDirection = velocityRef.current.clone().normalize();
    let targetSpeed = 0;
    let isOrbiting = false;

    let targetObj: Object3D | null = null;
    let targetWorldPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetWorldPos);
    }

    // === STATE: LIFTOFF (Vertical climb from Earth) ===
    if (stateRef.current === 'LIFTOFF') {
        targetSpeed = 5.0; // Slow vertical climb
        targetDirection = new Vector3(0, 1, 0); // Straight Up

        const earthPos = new Vector3();
        planetRefs.current['earth'].getWorldPosition(earthPos);

        // If we are high enough above Earth, switch to Traveling
        if (pos.y > earthPos.y + 10) {
            stateRef.current = 'TRAVELING';
        }
    }

    // === STATE: TRAVELING ===
    else if (stateRef.current === 'TRAVELING' && targetObj) {
       targetSpeed = TRAVEL_SPEED;

       const distToPlanet = pos.distanceTo(targetWorldPos);
       const safeRadius = getSafeOrbitRadius(tId!);

       // Calculate Entry Point for Counter-Clockwise (Left) Orbit
       // To orbit CCW, we want to approach the RIGHT side of the planet relative to our path,
       // then turn LEFT into the orbit.

       // Vector to planet
       const toPlanet = new Vector3().subVectors(targetWorldPos, pos);
       const dirToPlanet = toPlanet.clone().normalize();

       // Calculate a tangent point offset to the "Right"
       // Cross Up (0,1,0) with DirToPlanet gives vector to the Right
       const rightVector = new Vector3(0, 1, 0).cross(dirToPlanet).normalize();

       // Aim for point at Radius distance to the right
       const approachTarget = targetWorldPos.clone().add(rightVector.multiplyScalar(safeRadius));

       targetDirection = new Vector3().subVectors(approachTarget, pos).normalize();

       // Check arrival at tangent point
       if (distToPlanet < safeRadius + 2.0) {
           stateRef.current = 'ORBITING';
           orbitRadiusRef.current = safeRadius;
           orbitCenterRef.current.copy(targetWorldPos);

           // Calculate initial angle from the planet's center to current pos
           const relative = new Vector3().subVectors(pos, targetWorldPos);
           orbitAngleRef.current = Math.atan2(relative.z, relative.x);
           totalOrbitTraveledRef.current = 0;
       }
    }

    // === STATE: ORBITING (1.5 Loops) ===
    else if (stateRef.current === 'ORBITING' && targetObj) {
       isOrbiting = true;
       targetSpeed = ORBIT_SPEED;
       orbitCenterRef.current.copy(targetWorldPos);

       // Counter-Clockwise Rotation
       // Angle increases
       const angleStep = (targetSpeed / orbitRadiusRef.current) * delta;
       const nextAngle = orbitAngleRef.current + angleStep;

       const idealX = orbitCenterRef.current.x + Math.cos(nextAngle) * orbitRadiusRef.current;
       const idealZ = orbitCenterRef.current.z + Math.sin(nextAngle) * orbitRadiusRef.current;
       const idealY = orbitCenterRef.current.y; // Maintain level flight

       const idealPos = new Vector3(idealX, idealY, idealZ);

       targetDirection = new Vector3().subVectors(idealPos, pos).normalize();

       // Update trackers
       orbitAngleRef.current += angleStep;
       totalOrbitTraveledRef.current += angleStep;

       // Exit Condition: 1.5 Loops = 1.5 * 2 * PI = 3 PI
       if (totalOrbitTraveledRef.current > Math.PI * 3.0) {
           stateRef.current = 'LEAVING';
       }
    }

    // === STATE: LEAVING (Transition to next) ===
    else if (stateRef.current === 'LEAVING') {
       targetSpeed = TRAVEL_SPEED;
       // Continue tangent for a brief moment to clear orbit
       // Inertia handles this mostly

       if (missionQueueRef.current.length > 0) {
           const nextId = missionQueueRef.current.shift()!;
           currentTargetIdRef.current = nextId;

           const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
           setMissionProgress(prev => ({ 
               current: prev.current + 1, 
               total: prev.total, 
               targetName: pName
           }));

           stateRef.current = 'TRAVELING';
       } else {
           // No more targets? If final target was Earth, we are done.
           if (currentTargetIdRef.current === 'earth') {
               stateRef.current = 'COMPLETED';
           } else {
               // Should not happen with current logic, but fallback
               stateRef.current = 'COMPLETED';
           }
       }
    }

    else if (stateRef.current === 'COMPLETED') {
        // Fade out or just callback
        targetSpeed = 0;
        onMissionComplete();
        return;
    }

    // --- 3. MOVEMENT APPLICATION ---

    // Smooth Speed
    speedRef.current = MathUtils.lerp(speedRef.current, targetSpeed, delta * 2.0);

    // Smooth Rotation
    const currentDirNormalized = velocityRef.current.clone().normalize();
    // Stronger steering when close to orbit to maintain curve
    const steerFactor = isOrbiting ? TURN_SPEED * 2 : TURN_SPEED;

    const smoothedDir = new Vector3().lerpVectors(currentDirNormalized, targetDirection, steerFactor * delta).normalize();

    velocityRef.current = smoothedDir.multiplyScalar(speedRef.current);

    const moveStep = velocityRef.current.clone().multiplyScalar(delta);
    groupRef.current.position.add(moveStep);

    // Orientation
    const dummyObj = new Object3D();
    dummyObj.position.copy(pos);
    dummyObj.lookAt(pos.clone().add(smoothedDir));
    groupRef.current.quaternion.slerp(dummyObj.quaternion, 5.0 * delta);


    // --- 4. BANKING (Left Turn = Left Bank) ---
    // If entering orbit (CCW), we are constantly turning Left.
    // Cross(Forward, Up) -> Right Vector.
    // Cross(Forward, Target) -> Up/Down vector.
    // Simpler: Just check if we are turning left or right relative to UP.

    let desiredBank = 0;
    if (speedRef.current > 1 && stateRef.current !== 'LIFTOFF') {
        const localTarget = targetDirection.clone().applyQuaternion(groupRef.current.quaternion.clone().invert());
        // localTarget.x < 0 means target is to the LEFT.
        // Bank LEFT means Z rotation positive.
        // So desiredBank = -localTarget.x * Factor
        desiredBank = -localTarget.x * BANK_FACTOR;
    }

    if (isOrbiting) {
        desiredBank = Math.PI / 4; // Hard bank Left (Positive Z) for CCW orbit
    }

    currentBankingRef.current = MathUtils.lerp(currentBankingRef.current, desiredBank, delta * 2.0);
    if (shipModelRef.current) {
        shipModelRef.current.rotation.z = currentBankingRef.current;
    }


    // --- 5. CAMERA ---
    // Update Display
    if (Math.round(speedRef.current * 1000) !== currentSpeedDisplay) {
        setCurrentSpeedDisplay(Math.round(speedRef.current * 1000));
    }

    const targetCamDist = isOrbiting ? 25 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const heightOffset = 6;

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.1);
    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(20));
    state.camera.lookAt(lookTarget);
  });

  const tName = missionProgress.targetName;

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* Countdown Overlay */}
        {countdownText && (
             <Html center zIndexRange={[200, 0]}>
                <div className="flex items-center justify-center">
                   <h1 className="text-8xl font-black text-transparent bg-clip-text bg-gradient-to-b from-yellow-300 to-red-600 drop-shadow-[0_0_20px_rgba(255,100,0,0.8)] animate-pulse font-mono tracking-widest whitespace-nowrap scale-150">
                     {countdownText}
                   </h1>
                </div>
             </Html>
        )}

        {/* HUD */}
        {stateRef.current !== 'COUNTDOWN' && (
            <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
                <div className="flex flex-col items-start pointer-events-none select-none gap-2">
                    <div className="flex flex-col items-start">
                        <div className="bg-cyan-900/40 border-l-2 border-cyan-400 backdrop-blur-sm px-3 py-1 mb-1 transform skew-x-[-10deg]">
                        <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Velocity</span>
                        <div className="text-xl font-bold text-white font-mono leading-none flex items-baseline gap-1">
                            {currentSpeedDisplay.toLocaleString()} 
                            <span className="text-[10px] text-cyan-400">KM/H</span>
                        </div>
                        </div>
                    </div>

                    {missionProgress.total > 0 && (
                    <div className="bg-blue-900/40 border-l-2 border-blue-400 backdrop-blur-sm px-3 py-1 transform skew-x-[-10deg]">
                        <span className="text-[10px] text-blue-200 font-mono tracking-widest uppercase">Target</span>
                        <div className="text-sm font-bold text-white leading-tight mt-0.5">
                            {tName.split(' ')[0]} 
                            <span className="text-[10px] ml-1 text-blue-300 opacity-80">
                            (第{missionProgress.current}站 / 共{missionProgress.total}站)
                            </span>
                        </div>
                    </div>
                    )}
                </div>
            </Html>
        )}

        {/* Inner group for banking animations (Rolling) */}
        <group ref={shipModelRef}>
            {/* Rotate entire ship mesh 90deg X so Y-up geometry faces Z-forward movement */}
            <group rotation={[Math.PI / 2, 0, 0]}>

                {/* 1. Main Hull */}
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial 
                    color="#e2e8f0" 
                    metalness={0.9} 
                    roughness={0.2} 
                    clearcoat={1.0}
                    clearcoatRoughness={0.1}
                  />
                </mesh>

                {/* NAME LABELS */}
                <group position={[0, 0, 0.36]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" lineHeight={1} outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" lineHeight={1} outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* 2. Nose Cone */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* 3. Forward Flaps */}
                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" roughness={0.4} /></mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" roughness={0.4} /></mesh>
                </group>

                {/* 4. Aft Flaps */}
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" roughness={0.4} /></mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" roughness={0.4} /></mesh>
                </group>

                {/* 5. Engines */}
                <group position={[0, -0.85, 0]}>
                   <mesh position={[0, 0, 0]}><cylinderGeometry args={[0.25, 0.2, 0.1, 16]} /><meshStandardMaterial color="#111" /></mesh>
                   <mesh position={[0.1, -0.1, 0]}><cylinderGeometry args={[0.06, 0.08, 0.2, 8]} /><meshStandardMaterial color="#222" /></mesh>
                   <mesh position={[-0.1, -0.1, 0]}><cylinderGeometry args={[0.06, 0.08, 0.2, 8]} /><meshStandardMaterial color="#222" /></mesh>
                   <mesh position={[0, -0.1, 0.12]}><cylinderGeometry args={[0.06, 0.08, 0.2, 8]} /><meshStandardMaterial color="#222" /></mesh>
                </group>

                {/* 6. Raptor Engine Flame - Dynamic Scaling based on Speed */}
                <group scale={[1, 1 + (speedRef.current / 30), 1]}>
                    <mesh position={[0, -1.6, 0]}>
                      <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                      <meshBasicMaterial color="#8B5CF6" transparent opacity={0.4} depthWrite={false} blending={AdditiveBlending} />
                    </mesh>
                    <mesh position={[0, -1.4, 0]}>
                      <cylinderGeometry args={[0.1, 0.0, 1.0, 16, 1, true]} /> 
                      <meshBasicMaterial color="#06b6d4" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                    </mesh>
                </group>

                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={4} />
            </group>

            {/* TRAIL */}
            <group position={[0, 0, -1.2]}>
              <Trail width={0.4} length={12} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>
    </>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, Quaternion, MathUtils } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine including Countdown and Liftoff
type ShipState = 'PLANNING' | 'COUNTDOWN' | 'LIFTOFF' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });
  const [countdownText, setCountdownText] = useState<string | null>(null); // For 3, 2, 1

  // Refs for loop variables
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // --- PHYSICS REFS ---
  const velocityRef = useRef(new Vector3(0, 0, 0));
  const speedRef = useRef(0); 
  const currentBankingRef = useRef(0); 

  // Orbiting specific
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const orbitCenterRef = useRef(new Vector3());
  const totalOrbitTraveledRef = useRef(0);

  // Navigation fixed target (Prevents wobble by locking the destination point)
  const approachTargetRef = useRef<Vector3 | null>(null);

  // Camera
  const camDistRef = useRef(16); 

  // Constants
  const TRAVEL_SPEED = 20; 
  const ORBIT_SPEED = 12; 
  const TURN_SPEED = 1.0; // Reduced for smoother final alignment
  const BANK_FACTOR = 3.5; 

  // Generate route: Earth -> [Mars, Jupiter, Saturn, Uranus, Neptune] -> Earth
  // Exclude: Mercury, Venus, Pluto
  const generateMission = () => {
     // Get valid outer planets
     const outerPlanets = ['mars', 'jupiter', 'saturn', 'uranus', 'neptune'];

     // Shuffle
     for (let i = outerPlanets.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [outerPlanets[i], outerPlanets[j]] = [outerPlanets[j], outerPlanets[i]];
     }

     // Add Earth at the end
     outerPlanets.push('earth');
     return outerPlanets;
  };

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 15; 
     if (p.id === 'earth') return 5.0; // Tighter orbit for Earth
     // Ensure orbit is outside rings/moons
     if (p.hasRings) return p.size * 2.5 + 4.0; 
     return p.size * 3.0 + 3.0; 
  };

  // Countdown Logic
  useEffect(() => {
     if (stateRef.current === 'PLANNING') {
         stateRef.current = 'COUNTDOWN';

         const schedule = [
             { time: 500, text: "3" },
             { time: 1500, text: "2" },
             { time: 2500, text: "1" },
             { time: 3500, text: "起飞!" },
         ];

         schedule.forEach(item => {
             setTimeout(() => setCountdownText(item.text), item.time);
         });

         setTimeout(() => {
             setCountdownText(null);
             stateRef.current = 'LIFTOFF';

             // Initialize Mission Queue
             missionQueueRef.current = generateMission();
             const nextId = missionQueueRef.current.shift()!;
             currentTargetIdRef.current = nextId;

             const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
             setMissionProgress({ current: 1, total: 6, targetName: pName }); 

         }, 4500);
     }
  }, []);

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const pos = groupRef.current.position;

    // --- 0. INITIALIZATION: Spawn at Earth Surface ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        // Spawn effectively "Landed" on top
        if (startPos.lengthSq() > 1) { 
             startPos.y += 1.5; // Just above surface
             groupRef.current.position.copy(startPos);

             // Point UP initially
             velocityRef.current.set(0, 1, 0).normalize();

             const dummy = new Object3D();
             dummy.position.copy(startPos);
             dummy.lookAt(startPos.clone().add(velocityRef.current));
             groupRef.current.quaternion.copy(dummy.quaternion);

             initializedRef.current = true;
        }
      }
      return;
    }

    if (stateRef.current === 'COUNTDOWN') {
        // Just hover slightly or rumble
        groupRef.current.position.y += Math.sin(state.clock.elapsedTime * 20) * 0.005;
        return;
    }

    // --- 2. PHYSICS ENGINE ---

    let targetDirection = velocityRef.current.clone().normalize();
    let targetSpeed = 0;
    let isOrbiting = false;

    let targetObj: Object3D | null = null;
    let targetWorldPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetWorldPos);
    }

    // === STATE: LIFTOFF (Vertical climb from Earth) ===
    if (stateRef.current === 'LIFTOFF') {
        targetSpeed = 5.0; // Slow vertical climb
        targetDirection = new Vector3(0, 1, 0); // Straight Up

        const earthPos = new Vector3();
        planetRefs.current['earth'].getWorldPosition(earthPos);

        // If we are high enough above Earth, switch to Traveling
        if (pos.y > earthPos.y + 10) {
            stateRef.current = 'TRAVELING';
            approachTargetRef.current = null; // Ensure target is reset
        }
    }

    // === STATE: TRAVELING ===
    else if (stateRef.current === 'TRAVELING' && targetObj) {
       targetSpeed = TRAVEL_SPEED;

       // OPTIMIZATION: Calculate Entry Point Once and FREEZE it to prevent wobble
       if (!approachTargetRef.current) {
           const safeRadius = getSafeOrbitRadius(tId!);

           // Vector to planet
           const toPlanet = new Vector3().subVectors(targetWorldPos, pos);
           const dirToPlanet = toPlanet.clone().normalize();

           // Calculate a tangent point offset to the "Right"
           // Cross Up (0,1,0) with DirToPlanet gives vector to the Right
           const rightVector = new Vector3(0, 1, 0).cross(dirToPlanet).normalize();

           // Aim for point at Radius distance to the right
           // This fixed point will be our stable target for the entire leg
           const fixedTarget = targetWorldPos.clone().add(rightVector.multiplyScalar(safeRadius));
           approachTargetRef.current = fixedTarget;
       }

       const dest = approachTargetRef.current;
       const distToEntry = pos.distanceTo(dest);

       targetDirection = new Vector3().subVectors(dest, pos).normalize();

       // Check arrival at tangent point
       if (distToEntry < 2.0) {
           stateRef.current = 'ORBITING';
           approachTargetRef.current = null; // Clear for next phase

           orbitRadiusRef.current = getSafeOrbitRadius(tId!);
           orbitCenterRef.current.copy(targetWorldPos);

           // Calculate initial angle from the planet's center to current pos
           const relative = new Vector3().subVectors(pos, targetWorldPos);
           orbitAngleRef.current = Math.atan2(relative.z, relative.x);
           totalOrbitTraveledRef.current = 0;
       }
    }

    // === STATE: ORBITING (1.5 Loops) ===
    else if (stateRef.current === 'ORBITING' && targetObj) {
       isOrbiting = true;
       targetSpeed = ORBIT_SPEED;
       orbitCenterRef.current.copy(targetWorldPos);

       // Counter-Clockwise Rotation
       // Angle increases
       const angleStep = (targetSpeed / orbitRadiusRef.current) * delta;
       const nextAngle = orbitAngleRef.current + angleStep;

       const idealX = orbitCenterRef.current.x + Math.cos(nextAngle) * orbitRadiusRef.current;
       const idealZ = orbitCenterRef.current.z + Math.sin(nextAngle) * orbitRadiusRef.current;
       const idealY = orbitCenterRef.current.y; // Maintain level flight

       const idealPos = new Vector3(idealX, idealY, idealZ);

       targetDirection = new Vector3().subVectors(idealPos, pos).normalize();

       // Update trackers
       orbitAngleRef.current += angleStep;
       totalOrbitTraveledRef.current += angleStep;

       // Exit Condition: 1.5 Loops = 1.5 * 2 * PI = 3 PI
       if (totalOrbitTraveledRef.current > Math.PI * 3.0) {
           stateRef.current = 'LEAVING';
       }
    }

    // === STATE: LEAVING (Transition to next) ===
    else if (stateRef.current === 'LEAVING') {
       targetSpeed = TRAVEL_SPEED;
       // Continue tangent for a brief moment to clear orbit
       // Inertia handles this mostly

       if (missionQueueRef.current.length > 0) {
           const nextId = missionQueueRef.current.shift()!;
           currentTargetIdRef.current = nextId;

           const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
           setMissionProgress(prev => ({ 
               current: prev.current + 1, 
               total: prev.total, 
               targetName: pName
           }));

           stateRef.current = 'TRAVELING';
           approachTargetRef.current = null; // Reset for new target
       } else {
           // No more targets? If final target was Earth, we are done.
           if (currentTargetIdRef.current === 'earth') {
               stateRef.current = 'COMPLETED';
           } else {
               // Should not happen with current logic, but fallback
               stateRef.current = 'COMPLETED';
           }
       }
    }

    else if (stateRef.current === 'COMPLETED') {
        // Fade out or just callback
        targetSpeed = 0;
        onMissionComplete();
        return;
    }

    // --- 3. MOVEMENT APPLICATION ---

    // Smooth Speed
    speedRef.current = MathUtils.lerp(speedRef.current, targetSpeed, delta * 2.0);

    // Smooth Rotation
    const currentDirNormalized = velocityRef.current.clone().normalize();
    // Stronger steering when close to orbit to maintain curve, softer when traveling long distance
    const steerFactor = isOrbiting ? TURN_SPEED * 2.5 : TURN_SPEED;

    const smoothedDir = new Vector3().lerpVectors(currentDirNormalized, targetDirection, steerFactor * delta).normalize();

    velocityRef.current = smoothedDir.multiplyScalar(speedRef.current);

    const moveStep = velocityRef.current.clone().multiplyScalar(delta);
    groupRef.current.position.add(moveStep);

    // Orientation
    const dummyObj = new Object3D();
    dummyObj.position.copy(pos);
    dummyObj.lookAt(pos.clone().add(smoothedDir));
    groupRef.current.quaternion.slerp(dummyObj.quaternion, 5.0 * delta);


    // --- 4. BANKING (Left Turn = Left Bank) ---
    // If entering orbit (CCW), we are constantly turning Left.
    // Cross(Forward, Up) -> Right Vector.
    // Cross(Forward, Target) -> Up/Down vector.
    // Simpler: Just check if we are turning left or right relative to UP.

    let desiredBank = 0;
    if (speedRef.current > 1 && stateRef.current !== 'LIFTOFF') {
        const localTarget = targetDirection.clone().applyQuaternion(groupRef.current.quaternion.clone().invert());
        // localTarget.x < 0 means target is to the LEFT.
        // Bank LEFT means Z rotation positive.
        // So desiredBank = -localTarget.x * Factor
        desiredBank = -localTarget.x * BANK_FACTOR;
    }

    if (isOrbiting) {
        desiredBank = Math.PI / 4; // Hard bank Left (Positive Z) for CCW orbit
    }

    currentBankingRef.current = MathUtils.lerp(currentBankingRef.current, desiredBank, delta * 2.0);
    if (shipModelRef.current) {
        shipModelRef.current.rotation.z = currentBankingRef.current;
    }


    // --- 5. CAMERA ---
    // Update Display
    if (Math.round(speedRef.current * 1000) !== currentSpeedDisplay) {
        setCurrentSpeedDisplay(Math.round(speedRef.current * 1000));
    }

    const targetCamDist = isOrbiting ? 25 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const heightOffset = 6;

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.1);
    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(20));
    state.camera.lookAt(lookTarget);
  });

  const tName = missionProgress.targetName;

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* Countdown Overlay */}
        {countdownText && (
             <Html center zIndexRange={[200, 0]}>
                <div className="flex items-center justify-center">
