// Camera FlyTo Logic
const CameraFlyTo = ({ target, planetRefs, controlsRef, setTarget }: { target: { id: string, size: number } | null, planetRefs: any, controlsRef: any, setTarget: any }) => {
  useFrame((state, delta) => {
    if (!target) return;
    const { id, size } = target;
    const targetObj = planetRefs.current[id];

    // If we can't find object, abort
    if (!targetObj) {
      setTarget(null);
      return;
    }

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    // Current camera state
    const currentCamPos = state.camera.position.clone();

    // Desired camera state
    // Direction from planet to camera (preserve current angle mostly)
    const dir = new Vector3().subVectors(currentCamPos, targetPos).normalize();

    // Zoom distance: 4x size is decent for overview, max at least 5 units
    // For Tiangong (0.1) -> 0.4 is too close, clamp to 3 minimum
    // For Sun (8.0) -> 32
    const zoomDist = Math.max(size * 4, 6.0); 
    const desiredCamPos = targetPos.clone().add(dir.multiplyScalar(zoomDist));

    // Smooth step
    const lerpFactor = 4.0 * delta;

    // Move controls target to planet center
    controlsRef.current.target.lerp(targetPos, lerpFactor);

    // Move camera position
    state.camera.position.lerp(desiredCamPos, lerpFactor);

    controlsRef.current.update();

    // Completion check: Close enough to target pos AND look target
    if (state.camera.position.distanceTo(desiredCamPos) < 0.5 && 
        controlsRef.current.target.distanceTo(targetPos) < 0.1) {
       setTarget(null); // Stop forcing animation
    }
  });
  return null;
}

// Updated Controller with Smoothing to prevent Jitter
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  // Store smoothed values to prevent camera shaking from noisy hand data
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      // Smoothing factor: Lower = Smoother/Slower, Higher = More responsive/Jittery
      // 5.0 * delta gives a nice weighted average over ~0.2 seconds
      const smoothFactor = 5.0 * delta;

      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      // Use a small deadzone to stop movement completely when hands are steady
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      const isActive = activeDx !== 0 || activeDy !== 0;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // Hand Left/Right (dx) -> Rotate Azimuth
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);

             // Hand Up/Down (dy) -> Rotate Polar Angle
             // Requirement: "Up movement -> Camera angle moves down"
             // Hand Up (dy < 0). 'activeDy' is negative.
             // We want Camera Down -> Increase Polar Angle (towards PI/2).
             // Subtracting negative activeDy adds to the angle.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);

          } else if (gestureType === 'zoom') {
             // ZOOM MODE
             const zoomSensitivity = 0.015; // Adjusted sensitivity

             // Smooth zoom application
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);

             // activeDy corresponds to change in distance between hands (Spread > 0, Close < 0)
             // Requirement: "Hands spread and lengthen distance -> view zooms in"
             if (activeDy > 0) {
                 // Spread -> Zoom In (Dolly In)
                 controlsRef.current.dollyIn(speed);
             } else {
                 // Close -> Zoom Out (Dolly Out)
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); // AR Mode State

  // Camera Focus State
  const [focusTarget, setFocusTarget] = useState<{ id: string, size: number } | null>(null);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  // Safety Effect: Ensure body background is black on mount, and transparent on AR
  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  // Helper to find planet size
  const getPlanetSize = (id: string): number => {
      if (id === 'sun') return SUN_DATA.size;
      if (id === 'moon') return MOON_DATA.size;
      if (id === 'tiangong') return TIANGONG_DATA.size;

      const p = PLANETS.find(x => x.id === id);
      if (p) return p.size;

      const jm = JUPITER_MOONS.find(x => x.id === id);
      if (jm) return jm.size;

      const sm = SATURN_MOONS.find(x => x.id === id);
      if (sm) return sm.size;

      return 2; // default
  };

  const handleDoubleClick = (id: string) => {
      const size = getPlanetSize(id);
      setFocusTarget({ id, size });
      // Also ensure it is selected (paused and UI shown)
      handleSelect(id);
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const toggleOrbits = () => {
    setShowOrbits(!showOrbits);
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      // If turning off gesture mode, also turn off AR
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
       // Reset focus if we start flying
       setFocusTarget(null);
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;

    // Check main planets
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    // Check Jupiter's moons
    const jMoon = JUPITER_MOONS.find(m => m.id === selectedPlanetId);
    if (jMoon) return jMoon;
    // Check Saturn's moons
    return SATURN_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
        showOrbits={showOrbits}
        toggleOrbits={toggleOrbits}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      {/* 
         Canvas needs alpha: true for transparency.
         When AR Mode is ON, we hide the Skybox and opaque layers so the video behind shows through.
         onPointerMissed handles clicking empty space to deselect/close popups.
      */}
      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          // If we clicked on empty space (not a mesh), close the info panel
          if (selectedPlanetId) {
            handleClose();
          }
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={2}
            maxDistance={500}
            maxPolarAngle={Math.PI / 1.8}
            // Slower auto-rotate for better default experience
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive && !focusTarget}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <CameraFlyTo 
             target={focusTarget} 
             planetRefs={planetRefs} 
             controlsRef={controlsRef} 
             setTarget={setFocusTarget} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Always show, they look nice floating in room) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Skybox) - HIDE IN AR MODE */}
          {!isARMode && <Skybox />}

          {/* 3. Magical Dust */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             onDoubleClick={handleDoubleClick}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
             planetRefs={planetRefs}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              onDoubleClick={handleDoubleClick}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
              showOrbit={showOrbits}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, MathUtils, InstancedMesh, DynamicDrawUsage, Matrix4, PerspectiveCamera } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS, SUN_DATA } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

type ShipState = 'INIT' | 'WARP_ACCEL' | 'WARP_CRUISE' | 'WARP_DECEL' | 'ORBIT_ENTRY' | 'ORBITING' | 'LEAVING';

// Configuration
const TOUR_ROUTE = ['mars', 'jupiter', 'saturn', 'uranus', 'neptune', 'sun', 'earth'];
const ORBIT_LOOPS = 1.0; // How many loops around the planet
const WARP_SPEED_MAX = 60; // Max travel speed
const ORBIT_SPEED = 10;    // Orbit speed
const SUN_ORBIT_RADIUS_MULT = 1.8; // Sun needs bigger clearance
const PLANET_ORBIT_RADIUS_MULT = 3.0; // Standard planet clearance

// --- Warp Tunnel Effect Component ---
const WarpTunnel: React.FC<{ speed: number; active: boolean }> = ({ speed, active }) => {
  const count = 200;
  const meshRef = useRef<InstancedMesh>(null);
  const { camera } = useThree();

  // Initialize particles around the camera
  const particles = useMemo(() => {
    return new Array(count).fill(0).map(() => ({
      pos: new Vector3(
        MathUtils.randFloatSpread(40),
        MathUtils.randFloatSpread(40),
        MathUtils.randFloatSpread(100)
      ),
      velocity: MathUtils.randFloat(0.5, 1.5)
    }));
  }, []);

  const dummy = useMemo(() => new Matrix4(), []);

  useFrame(() => {
    if (!meshRef.current || !active) {
       if (meshRef.current) meshRef.current.visible = false;
       return;
    }
    meshRef.current.visible = true;

    // Particles always relative to camera but moving backwards
    const camPos = camera.position;
    const camQuat = camera.quaternion;
    const forward = new Vector3(0, 0, -1).applyQuaternion(camQuat); 

    // Calculate "Warp Factor" based on ship speed (0 to 1)
    const warpFactor = MathUtils.clamp((speed - 10) / 40, 0, 1);
    const stretch = 1 + warpFactor * 10; // Stretch lines when fast

    particles.forEach((p, i) => {
        // Move particle towards camera Z-local
        p.pos.z += p.velocity * (1 + speed * 0.5); 

        // Reset if passed camera
        if (p.pos.z > 20) {
            p.pos.z = -150;
            p.pos.x = MathUtils.randFloatSpread(60);
            p.pos.y = MathUtils.randFloatSpread(60);
        }

        // Apply to local camera space
        dummy.makeIdentity();
        dummy.makeScale(0.05, 0.05, stretch); // Long streaks
        dummy.setPosition(p.pos.x, p.pos.y, p.pos.z);

        // Transform to world space based on camera orientation
        // Actually, simpler to just parent it to camera? 
        // For performance in React Three Fiber, we usually simulate local space in World Space manually
        // But here, let's just keep it simple: We attach this mesh to the Starship group instead?
        // No, let's assume this component is rendered INSIDE the Starship group for relative transform.

        meshRef.current!.setMatrixAt(i, dummy);
    });
    meshRef.current.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
       <boxGeometry args={[1, 1, 1]} />
       <meshBasicMaterial color="#80eaff" transparent opacity={0.3} blending={AdditiveBlending} />
    </instancedMesh>
  );
};


export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // State Refs
  const stateRef = useRef<ShipState>('INIT');
  const routeIndexRef = useRef(0);
  const initializedRef = useRef(false);

  // Physics Refs
  const currentSpeedRef = useRef(0);
  const targetSpeedRef = useRef(0);

  // Orbit Logic Refs
  const orbitCenterRef = useRef(new Vector3());
  const orbitRadiusRef = useRef(10);
  const orbitAngleRef = useRef(0);
  const orbitProgressRef = useRef(0);

  // Camera Refs
  const cameraRef = useRef<any>(null); // We will manipulate main camera via useThree if needed, or use local
  const defaultFov = 45;
  const warpFov = 75; // Wider FOV for speed sensation

  // Three.js State
  const { camera, set: setThreeState } = useThree();

  // Helper: Get Planet Data
  const getPlanetData = (id: string) => {
      if (id === 'sun') return SUN_DATA;
      return PLANETS.find(p => p.id === id);
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 1. INITIALIZATION: Spawn at Earth ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { 
             // Spawn slightly above Earth
             startPos.y += 5.0; 
             startPos.x += 5.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;
             stateRef.current = 'WARP_ACCEL'; // Start mission immediately
        }
      }
      return; 
    }

    // --- 2. STATE MACHINE LOGIC ---

    // Get Current Target
    const targetId = TOUR_ROUTE[routeIndexRef.current];
    const targetData = getPlanetData(targetId);
    const targetObj = planetRefs.current[targetId];

    if (!targetObj) {
        // Wait for object to load
        return;
    }

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);
    const currentPos = groupRef.current.position.clone();
    const distToTarget = currentPos.distanceTo(targetPos);

    // Calculate desired Orbit Radius
    let desiredRadius = (targetData?.size || 5) * PLANET_ORBIT_RADIUS_MULT;
    if (targetId === 'sun') desiredRadius = SUN_DATA.size * SUN_ORBIT_RADIUS_MULT;
    if (targetId === 'saturn') desiredRadius += 5; // Extra clearance for rings

    // --- STATE HANDLERS ---

    if (stateRef.current === 'WARP_ACCEL' || stateRef.current === 'WARP_CRUISE') {
        // FLYING TOWARDS PLANET

        // Calculate point to enter orbit (tangent point)
        const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();
        const entryPoint = targetPos.clone().sub(dirToPlanet.multiplyScalar(desiredRadius));
        const distToEntry = currentPos.distanceTo(entryPoint);

        // Speed Logic
        if (stateRef.current === 'WARP_ACCEL') {
            targetSpeedRef.current = WARP_SPEED_MAX;
            if (currentSpeedRef.current > WARP_SPEED_MAX * 0.9) stateRef.current = 'WARP_CRUISE';
        }

        // Transition to Decel?
        if (distToEntry < 60) {
            stateRef.current = 'WARP_DECEL';
        }

        // Movement
        const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();

        // Acceleration smoothing
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, targetSpeedRef.current, delta * 1.5);

        groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

        // Look at destination
        const lookTarget = currentPos.clone().add(moveDir);
        const dummyQ = new Object3D();
        dummyQ.position.copy(currentPos);
        dummyQ.lookAt(lookTarget);
        groupRef.current.quaternion.slerp(dummyQ.quaternion, delta * 3.0);

        // Roll effect while turning
        if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta);
        }

    } else if (stateRef.current === 'WARP_DECEL') {
        // SLOWING DOWN FOR APPROACH
        const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();
        const entryPoint = targetPos.clone().sub(dirToPlanet.multiplyScalar(desiredRadius)); // Re-calc for precision
        const distToEntry = currentPos.distanceTo(entryPoint);

        targetSpeedRef.current = ORBIT_SPEED;
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, targetSpeedRef.current, delta * 2.0);

        const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
        groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

        // Smooth LookAt
        const dummyQ = new Object3D();
        dummyQ.position.copy(currentPos);
        dummyQ.lookAt(entryPoint);
        groupRef.current.quaternion.slerp(dummyQ.quaternion, delta * 5.0);

        if (distToEntry < 2.0) {
            // Hit entry point
            stateRef.current = 'ORBITING';
            orbitRadiusRef.current = desiredRadius;
            orbitCenterRef.current.copy(targetPos);

            // Calculate initial angle relative to planet
            const relPos = new Vector3().subVectors(currentPos, targetPos);
            orbitAngleRef.current = Math.atan2(relPos.z, relPos.x);
            orbitProgressRef.current = 0;
        }

    } else if (stateRef.current === 'ORBITING') {
        // CIRCLING PLANET
        targetSpeedRef.current = ORBIT_SPEED;
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, targetSpeedRef.current, delta * 2.0);

        // Circular motion
        const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
        const angleDelta = angularSpeed * delta;

        orbitAngleRef.current += angleDelta;
        orbitProgressRef.current += angleDelta;

        const nextX = orbitCenterRef.current.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
        const nextZ = orbitCenterRef.current.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
        const nextY = orbitCenterRef.current.y; // Keep level

        const nextPos = new Vector3(nextX, nextY, nextZ);
        groupRef.current.position.copy(nextPos);

        // Bank ship inwards
        const lookT = new Vector3(
             orbitCenterRef.current.x + Math.cos(orbitAngleRef.current + 0.1) * orbitRadiusRef.current,
             orbitCenterRef.current.y,
             orbitCenterRef.current.z + Math.sin(orbitAngleRef.current + 0.1) * orbitRadiusRef.current
        );
        const dummyQ = new Object3D();
        dummyQ.position.copy(nextPos);
        dummyQ.lookAt(lookT);
        groupRef.current.quaternion.slerp(dummyQ.quaternion, delta * 5.0);

        if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 3, delta * 2);
        }

        // Completion Check
        if (orbitProgressRef.current > Math.PI * 2 * ORBIT_LOOPS) {
            stateRef.current = 'LEAVING';
        }

    } else if (stateRef.current === 'LEAVING') {
        // TRANSITION TO NEXT
        routeIndexRef.current++;
        if (routeIndexRef.current >= TOUR_ROUTE.length) {
            onMissionComplete();
        } else {
            stateRef.current = 'WARP_ACCEL';
        }
    }


    // --- 3. DYNAMIC CINEMATIC CAMERA ---
    if (camera instanceof PerspectiveCamera) {

        const isWarping = stateRef.current.includes('WARP');
        const isOrbiting = stateRef.current === 'ORBITING';

        // A. Dynamic FOV
        const targetFov = isWarping ? warpFov : defaultFov;
        camera.fov = MathUtils.lerp(camera.fov, targetFov, delta * 2.0);
        camera.updateProjectionMatrix();

        // B. Camera Position & LookAt
        const shipPos = groupRef.current.position;
        const shipQuat = groupRef.current.quaternion;
        const backward = new Vector3(0, 0, -1).applyQuaternion(shipQuat).normalize(); // Model faces -Z usually? Check model.
        // Actually earlier `moveDir` logic implies forward is Z+? Let's check ship orientation.
        // In initialization: `forward` was (0,0,1).
        // Let's assume Ship Forward is Local Z+.
        const shipForward = new Vector3(0, 0, 1).applyQuaternion(shipQuat).normalize();

        let camOffset: Vector3;
        let lookAtOffset: Vector3;

        if (isOrbiting) {
            // ORBIT VIEW: High angle, side view, framing planet
            // We want to be "outside" the ship relative to the planet
            const vecToPlanet = new Vector3().subVectors(orbitCenterRef.current, shipPos).normalize();
            const vecTangent = shipForward.clone();

            // Cam Position: Behind and Above and slightly Away from planet
            const dist = 25;
            const height = 12;
            camOffset = shipForward.clone().multiplyScalar(-dist)
                        .add(new Vector3(0, height, 0))
                        .sub(vecToPlanet.multiplyScalar(10)); // Push away from planet to frame it

            // Look Target: Ahead of ship
            lookAtOffset = shipForward.clone().multiplyScalar(20);

        } else {
            // WARP VIEW: Tight follow, directly behind, rumble effect?
            const dist = isWarping ? 20 : 25;
            const height = isWarping ? 6 : 8;

            camOffset = shipForward.clone().multiplyScalar(-dist).add(new Vector3(0, height, 0));
            lookAtOffset = shipForward.clone().multiplyScalar(50);
        }

        const targetCamPos = shipPos.clone().add(camOffset);
        const targetLookAt = shipPos.clone().add(lookAtOffset);

        // Smooth Camera Follow
        camera.position.lerp(targetCamPos, delta * 3.0);

        // We need to manuall handle lookAt lerping
        // Create a dummy object to find target quaternion
        const dummyCam = new Object3D();
        dummyCam.position.copy(camera.position);
        dummyCam.lookAt(targetLookAt);
        camera.quaternion.slerp(dummyCam.quaternion, delta * 3.0);
    }

  });

  // HUD Info
  const targetId = TOUR_ROUTE[routeIndexRef.current];
  const targetName = getPlanetData(targetId)?.name || "Earth";
  const speedKmh = Math.round(currentSpeedRef.current * 2000); // Fake scale

  return (
    <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* WARP TUNNEL EFFECT (Local to ship) */}
        <group rotation={[0, Math.PI, 0]}> {/* Face backwards */}
            <WarpTunnel speed={currentSpeedRef.current} active={stateRef.current.includes('WARP')} />
        </group>

        {/* HUD */}
        <Html position={[0, 3, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-center gap-1 pointer-events-none select-none">
                {/* Status Bar */}
                <div className={`px-4 py-1 border-2 rounded-full backdrop-blur-md flex items-center gap-3 transition-colors duration-300
                    ${stateRef.current.includes('WARP') ? 'bg-cyan-900/60 border-cyan-400' : 'bg-orange-900/60 border-orange-400'}
                `}>
                    <div className={`w-2 h-2 rounded-full animate-pulse ${stateRef.current.includes('WARP') ? 'bg-cyan-300' : 'bg-orange-300'}`}></div>
                    <span className="text-white font-mono font-bold text-xs tracking-widest uppercase">
                        {stateRef.current.includes('WARP') ? 'WARP DRIVE ACTIVE' : 'ORBITAL CRUISE'}
                    </span>
                </div>

                {/* Destination Card */}
                <div className="flex flex-col items-center bg-black/50 p-2 rounded-lg border border-white/10 mt-1">
                     <span className="text-[9px] text-gray-400 uppercase tracking-widest">DESTINATION</span>
                     <span className="text-lg font-bold text-white drop-shadow-md">{targetName.split(' ')[0]}</span>
                     <div className="w-full h-[1px] bg-white/20 my-1"></div>
                     <span className="text-xs font-mono text-cyan-300">{speedKmh.toLocaleString()} KM/H</span>
                </div>
             </div>
        </Html>

        {/* SHIP MODEL */}
        <group ref={shipModelRef}>
            <group rotation={[Math.PI / 2, 0, 0]}>
                {/* Hull */}
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* Ship Name */}
                <group position={[0, 0, 0.36]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" lineHeight={1} outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" lineHeight={1} outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* Nose */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* Flaps */}
                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                </group>
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                </group>

                {/* Engines */}
                <group position={[0, -0.85, 0]}>
                   <mesh><cylinderGeometry args={[0.25, 0.2, 0.1, 16]} /><meshStandardMaterial color="#111" /></mesh>
                   {/* Main Engine Glow */}
                   <pointLight position={[0, -0.5, 0]} color="#00FFFF" intensity={stateRef.current.includes('WARP') ? 8 : 2} distance={5} />
                </group>

                {/* Engine Plume - Dynamic */}
                <mesh position={[0, -1.8, 0]} scale={[1, stateRef.current.includes('WARP') ? 2.5 : 1, 1]}>
                  <cylinderGeometry args={[0.15, 0.0, 1.8, 16, 1, true]} /> 
                  <meshBasicMaterial color="#06b6d4" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                </mesh>

                {/* Secondary Plume */}
                <mesh position={[0, -1.4, 0]} scale={[1, stateRef.current.includes('WARP') ? 2.0 : 1, 1]}>
                  <cylinderGeometry args={[0.08, 0.0, 1.2, 8, 1, true]} /> 
                  <meshBasicMaterial color="#ffffff" transparent opacity={0.8} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
            </group>

            {/* Trail Effect */}
            <group position={[0, 0, -1.2]}>
              <Trail width={stateRef.current.includes('WARP') ? 1.5 : 0.6} length={8} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
    </group>
  );
};

import React, { useRef, useMemo, useState, useLayoutEffect, useEffect } from 'react';
import { useFrame, extend } from '@react-three/fiber';
import { Mesh, Color, ShaderMaterial, Vector3, AdditiveBlending, TextureLoader, TorusGeometry, DoubleSide, Group, Object3D } from 'three';
import { Billboard, Html, shaderMaterial } from '@react-three/drei';
import { generateSunGlowTexture } from '../utils/textureGenerator';
import { SUN_DATA } from '../constants';

interface SunProps {
  onSelect: (id: string) => void;
  onDoubleClick: (id: string) => void;
  isSelected: boolean;
  isPaused: boolean;
  simulationSpeed: number;
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
}

// --- 1. SUN SURFACE SHADER ---
const SunShaderMaterial = shaderMaterial(
  { 
    uTime: 0, 
    uColorPrimary: new Color('#FFD700'),   
    uColorSecondary: new Color('#FF4500'), 
    uColorSunspot: new Color('#000000'),   
    uColorPenumbra: new Color('#8B0000'),  
    uColorBright: new Color('#FFFFFF')     
  },
  // Vertex Shader
  `
    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vViewPosition;

    void main() {
      vUv = uv;
      vNormal = normalize(normalMatrix * normal);
      vPosition = position;
      vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
      vViewPosition = -mvPosition.xyz;
      gl_Position = projectionMatrix * mvPosition;
    }
  `,
  // Fragment Shader
  `
    uniform float uTime;
    uniform vec3 uColorPrimary;
    uniform vec3 uColorSecondary;
    uniform vec3 uColorSunspot;
    uniform vec3 uColorPenumbra;
    uniform vec3 uColorBright;

    varying vec2 vUv;
    varying vec3 vNormal;
    varying vec3 vPosition;
    varying vec3 vViewPosition;

    // Ashima 3D Noise
    vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 mod289(vec4 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
    vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
    vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

    float snoise(vec3 v) { 
      const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
      const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);
      vec3 i  = floor(v + dot(v, C.yyy) );
      vec3 x0 = v - i + dot(i, C.xxx) ;
      vec3 g = step(x0.yzx, x0.xyz);
      vec3 l = 1.0 - g;
      vec3 i1 = min( g.xyz, l.zxy );
      vec3 i2 = max( g.xyz, l.zxy );
      vec3 x1 = x0 - i1 + C.xxx;
      vec3 x2 = x0 - i2 + C.yyy; 
      vec3 x3 = x0 - D.yyy;      
      i = mod289(i); 
      vec4 p = permute( permute( permute( 
                 i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
               + i.y + vec4(0.0, i1.y, i2.y, 1.0 )) 
               + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));
      float n_ = 0.142857142857; 
      vec3  ns = n_ * D.wyz - D.xzx;
      vec4 j = p - 49.0 * floor(p * ns.z * ns.z); 
      vec4 x_ = floor(j * ns.z);
      vec4 y_ = floor(j - 7.0 * x_ );    
      vec4 x = x_ *ns.x + ns.yyyy;
      vec4 y = y_ *ns.x + ns.yyyy;
      vec4 h = 1.0 - abs(x) - abs(y);
      vec4 b0 = vec4( x.xy, y.xy );
      vec4 b1 = vec4( x.zw, y.zw );
      vec4 s0 = floor(b0)*2.0 + 1.0;
      vec4 s1 = floor(b1)*2.0 + 1.0;
      vec4 sh = -step(h, vec4(0.0));
      vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
      vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;
      vec3 p0 = vec3(a0.xy,h.x);
      vec3 p1 = vec3(a0.zw,h.y);
      vec3 p2 = vec3(a1.xy,h.z);
      vec3 p3 = vec3(a1.zw,h.w);
      vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
      p0 *= norm.x;
      p1 *= norm.y;
      p2 *= norm.z;
      p3 *= norm.w;
      vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
      m = m * m;
      return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1), 
                                    dot(p2,x2), dot(p3,x3) ) );
    }

    void main() {
      // Noise
      float noiseScaleA = 6.0;
      float timeScaleA = 0.1;
      float n1 = snoise(vPosition * noiseScaleA + vec3(uTime * timeScaleA));
      float noiseScaleB = 2.0;
      float timeScaleB = 0.05;
      float n2 = snoise(vPosition * noiseScaleB - vec3(uTime * timeScaleB));
      float combinedNoise = n1 * 0.4 + n2 * 0.6; 
      float t = combinedNoise * 0.5 + 0.5;

      // Sunspots
      float umbraThreshold = 0.035;     
      float penumbraThreshold = 0.08; 
      float maskUmbra = smoothstep(umbraThreshold - 0.03, umbraThreshold + 0.02, t); 
      float maskPenumbra = smoothstep(penumbraThreshold - 0.04, penumbraThreshold + 0.04, t);

      float filamentNoise = snoise(vPosition * 12.0 + vec3(uTime * 0.02));
      vec3 detailedPenumbra = mix(uColorPenumbra, uColorSecondary * 0.8, filamentNoise * 0.4 + 0.4);

      vec3 surfaceColor = mix(uColorSecondary, uColorPrimary, t);

      float brightThreshold = 0.88; 
      float maskBright = smoothstep(brightThreshold, brightThreshold + 0.15, t);
      vec3 activeColor = mix(surfaceColor, uColorBright, maskBright);

      vec3 spotRegionColor = mix(detailedPenumbra, activeColor, maskPenumbra);
      vec3 finalBaseColor = mix(uColorSunspot, spotRegionColor, maskUmbra);

      // Limb Darkening
      vec3 viewDir = normalize(vViewPosition);
      float fresnel = dot(vNormal, viewDir); 
      float darkening = pow(fresnel, 0.45); 

      float rim = 1.0 - fresnel;
      vec3 rimColor = uColorPrimary * pow(rim, 3.5) * 0.8;

      gl_FragColor = vec4(finalBaseColor * darkening + rimColor, 1.0);
    }
  `
);

extend({ SunShaderMaterial });

