// Updated State Machine
type ShipState = 'PLANNING' | 'LEAVING_ORBIT' | 'ARC_TRAVEL' | 'ORBITING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // State Refs
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Orbit Refs
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);

  // Travel / Arc Refs
  const startPosRef = useRef(new Vector3());
  const endPosRef = useRef(new Vector3()); // Entry point of target
  const travelProgressRef = useRef(0);
  const travelDurationRef = useRef(5.0); // Seconds
  const cruiseHeightRef = useRef(40); // Height of the jump arc

  // Camera Refs
  const camDistRef = useRef(18); 

  // Helpers
  const MAX_ORBIT_SPEED = 1.5; // rad/s approx

  // 1. Generate Mission
  const generateMission = () => {
     // Exclude Mercury (too hot/close), ensure we visit interesting ones
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; 

     // Pick 4 random planets + Earth return
     for (let i = 0; i < 4; i++) {
        let next: string;
        let attempts = 0;
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);
        mission.push(next);
        lastPlanet = next;
     }
     mission.push('earth');
     return mission;
  };

  // 2. Safe Orbit Radius
  const getSafeOrbitRadius = (id: string) => {
     if (id === 'sun') return 20;
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 8; 
     // Add buffer for rings
     return p.hasRings ? p.size * 3.0 + 2.0 : p.size * 2.5 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- INITIALIZATION ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);
        if (startPos.lengthSq() > 1) { 
             // Start in orbit around Earth
             stateRef.current = 'ORBITING';
             currentTargetIdRef.current = 'earth';
             orbitRadiusRef.current = getSafeOrbitRadius('earth');

             // Calculate initial angle
             orbitAngleRef.current = Math.atan2(startPos.z, startPos.x);

             // Set Position
             const initialX = Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
             const initialZ = Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
             groupRef.current.position.set(initialX, 0, initialZ);
             groupRef.current.lookAt(new Vector3(0,0,0)); // Temp look at center

             initializedRef.current = true;

             // Immediately plan mission
             missionQueueRef.current = generateMission();
        }
      }
      return; 
    }

    // --- STATE MACHINE ---

    // A. ORBITING
    if (stateRef.current === 'ORBITING') {
       const tId = currentTargetIdRef.current;
       const targetObj = tId ? planetRefs.current[tId] : null;

       if (targetObj) {
          const targetWorldPos = new Vector3();
          targetObj.getWorldPosition(targetWorldPos);

          // Orbital Physics
          orbitAngleRef.current += delta * 0.8; // Constant orbital speed
          totalOrbitTraveledRef.current += delta * 0.8;

          const nextX = targetWorldPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
          const nextZ = targetWorldPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;

          const currentPos = new Vector3(nextX, targetWorldPos.y, nextZ);
          groupRef.current.position.copy(currentPos);

          // Look at tangent (Forward)
          const futureAngle = orbitAngleRef.current + 0.1;
          const lookX = targetWorldPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
          const lookZ = targetWorldPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;
          groupRef.current.lookAt(lookX, targetWorldPos.y, lookZ);

          // Bank inward
          if (shipModelRef.current) {
              shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, Math.PI / 5, delta * 2);
          }

          // Check for Departure (After ~1.5 orbits or if just starting)
          // If we have a mission queue, we leave.
          if (totalOrbitTraveledRef.current > Math.PI * 2.5 && missionQueueRef.current.length > 0) {
              const nextId = missionQueueRef.current.shift()!;
              const nextObj = planetRefs.current[nextId];

              if (nextObj) {
                 // Setup Travel
                 stateRef.current = 'ARC_TRAVEL';
                 currentTargetIdRef.current = nextId;

                 // Start Pos is current
                 startPosRef.current.copy(groupRef.current.position);

                 // Calculate End Pos (Entry point on new orbit)
                 // We aim for the side of the planet closest to us for efficiency
                 const nextWorldPos = new Vector3();
                 nextObj.getWorldPosition(nextWorldPos);

                 const dirToTarget = new Vector3().subVectors(nextWorldPos, startPosRef.current).normalize();
                 const nextRadius = getSafeOrbitRadius(nextId);

                 // Entry point: Target Pos - (Dir * Radius) -> Arrive at the "front"
                 endPosRef.current.copy(nextWorldPos).sub(dirToTarget.multiplyScalar(nextRadius));

                 // Calculate Orbit Angle at arrival for seamless transition
                 // We are arriving at vector -dirToTarget relative to planet
                 const relEntry = new Vector3().subVectors(endPosRef.current, nextWorldPos);
                 orbitAngleRef.current = Math.atan2(relEntry.z, relEntry.x);
                 orbitRadiusRef.current = nextRadius;

                 // Travel Config
                 travelProgressRef.current = 0;
                 const dist = startPosRef.current.distanceTo(endPosRef.current);
                 // Base duration on distance (min 3s, max 8s)
                 travelDurationRef.current = MathUtils.clamp(dist / 25, 3.0, 8.0);
                 // Height scales with distance (avoid sun)
                 cruiseHeightRef.current = Math.min(dist * 0.4, 60); 

                 // Reset Orbit counter for next planet
                 totalOrbitTraveledRef.current = 0;

                 // UI
                 const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
                 setMissionProgress(prev => ({
                    current: prev.current + 1,
                    total: 6, // 5 + 1
                    targetName: pName
                 }));
              }
          } else if (missionQueueRef.current.length === 0 && totalOrbitTraveledRef.current > Math.PI * 3) {
              stateRef.current = 'COMPLETED';
          }
       }
    }

    // B. ARC TRAVEL (The Jump)
    if (stateRef.current === 'ARC_TRAVEL') {
       travelProgressRef.current += delta / travelDurationRef.current;

       if (travelProgressRef.current >= 1.0) {
           // Arrived!
           stateRef.current = 'ORBITING';
           return;
       }

       const t = travelProgressRef.current;

       // Ease function for smooth start/stop
       // Sine ease in out
       const easeT = -(Math.cos(Math.PI * t) - 1) / 2;

       // Linear interpolation on X/Z plane
       const currentPos = new Vector3().lerpVectors(startPosRef.current, endPosRef.current, easeT);

       // Parabolic Arc on Y axis (The "Jump")
       // sin(0) = 0, sin(PI/2) = 1, sin(PI) = 0
       const heightOffset = Math.sin(t * Math.PI) * cruiseHeightRef.current;
       currentPos.y += heightOffset;

       groupRef.current.position.copy(currentPos);

       // Look Ahead Logic (Derivative)
       const nextT = Math.min(t + 0.01, 1.0);
       const nextEaseT = -(Math.cos(Math.PI * nextT) - 1) / 2;
       const nextPos = new Vector3().lerpVectors(startPosRef.current, endPosRef.current, nextEaseT);
       nextPos.y += Math.sin(nextT * Math.PI) * cruiseHeightRef.current;

       groupRef.current.lookAt(nextPos);

       // Bank Roll based on "Climb" or "Dive"
       // If climbing (t < 0.5), pitch up. If diving (t > 0.5), pitch down.
       // Actually let's roll a bit for style.
       if (shipModelRef.current) {
          // Roll effect: Spin slightly during warp? Or just level out.
          // Let's just level out the heavy banking from orbit
          shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 4);
       }

       // Update Speedometer (Fake speed based on arc height)
       const simulatedSpeed = 20 + (heightOffset * 2); 
       setCurrentSpeedDisplay(Math.round(simulatedSpeed * 50));
    }

    // C. COMPLETED
    if (stateRef.current === 'COMPLETED') {
        onMissionComplete();
        return;
    }

    // --- CAMERA ---
    // Smooth Follow Camera
    const isOrbiting = stateRef.current === 'ORBITING';

    // Target Distance: Close when orbiting, Far when Jumping
    const targetDist = isOrbiting ? 20 : 35;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetDist, delta * 1.5);

    const shipPos = groupRef.current.position.clone();
    const shipQuat = groupRef.current.quaternion.clone();

    // Get backward vector
    const back = new Vector3(0, 0, -1).applyQuaternion(shipQuat).negate().normalize();
    const up = new Vector3(0, 1, 0);

    // Position camera behind and above
    const camOffset = back.multiplyScalar(camDistRef.current).add(up.multiplyScalar(isOrbiting ? 8 : 15));
    const desiredCamPos = shipPos.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.1);
    state.camera.lookAt(shipPos.clone().add(back.multiplyScalar(-10))); // Look ahead of ship
  });

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* HUD */}
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none gap-2">
                <div className="flex flex-col items-start">
                    <div className="bg-cyan-900/60 border-l-4 border-cyan-400 backdrop-blur-md px-4 py-2 mb-1 transform skew-x-[-10deg] shadow-[0_0_15px_rgba(34,211,238,0.3)]">
                       <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Warp Speed</span>
                       <div className="text-2xl font-black text-white font-mono leading-none flex items-baseline gap-1 italic">
                          {currentSpeedDisplay.toLocaleString()} 
                          <span className="text-[10px] text-cyan-400 not-italic">KM/H</span>
                       </div>
                    </div>
                </div>

                {missionProgress.total > 0 && (
                   <div className="bg-blue-900/60 border-l-4 border-blue-500 backdrop-blur-md px-4 py-2 transform skew-x-[-10deg] shadow-[0_0_15px_rgba(59,130,246,0.3)]">
                      <span className="text-[10px] text-blue-200 font-mono tracking-widest uppercase">Destination</span>
                      <div className="text-lg font-bold text-white leading-tight mt-0.5 flex items-center gap-2">
                         <span>{missionProgress.targetName.split(' ')[0]}</span>
                         <div className="flex gap-1">
                             {Array.from({length: missionProgress.total}).map((_, i) => (
                                <div key={i} className={`w-1.5 h-1.5 rounded-full ${i < missionProgress.current ? 'bg-green-400' : 'bg-white/20'}`} />
                             ))}
                         </div>
                      </div>
                   </div>
                )}
             </div>
        </Html>

        {/* Ship Geometry */}
        <group ref={shipModelRef}>
            <group rotation={[Math.PI / 2, 0, 0]}>

                {/* Main Hull */}
                <mesh>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* Labels */}
                <group position={[0, 0, 0.36]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* Nose */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* Flaps */}
                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}><boxGeometry args={[0.2, 0.3, 0.05]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                </group>
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}><boxGeometry args={[0.3, 0.6, 0.08]} /><meshStandardMaterial color="#1a1a1a" /></mesh>
                </group>

                {/* Engine Glow (Dynamic) */}
                <mesh position={[0, -1.6, 0]}>
                  <cylinderGeometry args={[0.15, 0.0, 2.0, 16, 1, true]} /> 
                  <meshBasicMaterial color="#8B5CF6" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                <mesh position={[0, -1.4, 0]}>
                  <cylinderGeometry args={[0.1, 0.0, 1.5, 16, 1, true]} /> 
                  <meshBasicMaterial color="#06b6d4" transparent opacity={0.8} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={5} />
            </group>

            {/* Trail */}
            <group position={[0, 0, -1.2]}>
              <Trail width={0.6} length={12} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>
    </>
  );
};

import React, { useRef, useState, useMemo, useEffect } from 'react';
