export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const { camera } = useThree();
  const shipRef = useRef<Group>(null);

  // State
  const [hudMessage, setHudMessage] = useState("系统初始化...");
  const [hudDistance, setHudDistance] = useState("---");
  const [targetName, setTargetName] = useState("");
  const [warpCharge, setWarpCharge] = useState(0); // 0 to 100

  // Logic Refs
  const phaseRef = useRef<FlightPhase>('IDLE');
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);
  const velocityRef = useRef(new Vector3(0, 0, 0));
  const lookAtTargetRef = useRef(new Vector3());

  // Shake effect
  const shakeIntensityRef = useRef(0);

  // Initialize Mission
  useEffect(() => {
    // A curated "Grand Tour"
    const tour = ['mercury', 'venus', 'earth', 'mars', 'jupiter', 'saturn', 'uranus', 'neptune'];
    // Filter out start position if we are already there (usually starts at Earth or Sun, let's start fresh)
    missionQueueRef.current = tour;

    // Spawn ship near Sun initially for the "Grand Tour" start, or Earth?
    // Let's spawn near Earth for familiarity, then go to Mercury.
    if (planetRefs.current['sun'] && shipRef.current) {
        // Start high above the ecliptic for a view
        shipRef.current.position.set(0, 40, 60); 
        shipRef.current.lookAt(0, 0, 0);
    }

    // Start delay
    setTimeout(() => {
        nextTarget();
    }, 2000);
  }, []);

  const nextTarget = () => {
      if (missionQueueRef.current.length === 0) {
          setHudMessage("旅程结束 - 返回基地");
          onMissionComplete();
          return;
      }

      const nextId = missionQueueRef.current.shift()!;
      currentTargetIdRef.current = nextId;
      const p = PLANETS.find(x => x.id === nextId);
      setTargetName(p?.name || nextId);

      setHudMessage(`锁定目标: ${p?.name}`);
      phaseRef.current = 'ALIGNING';
  };

  useFrame((state, delta) => {
    if (!shipRef.current) return;

    // 1. FPV Camera Sync
    // The camera IS the pilot's eyes. It follows the ship group exactly.
    // We add a tiny bit of "head bob" or shake based on phase.
    const shakeX = (Math.random() - 0.5) * shakeIntensityRef.current;
    const shakeY = (Math.random() - 0.5) * shakeIntensityRef.current;
    const shakeZ = (Math.random() - 0.5) * shakeIntensityRef.current;

    camera.position.copy(shipRef.current.position).add(new Vector3(shakeX, shakeY, shakeZ));
    camera.quaternion.copy(shipRef.current.quaternion);

    // 2. Logic Machine
    const currentPos = shipRef.current.position.clone();
    let targetObj = currentTargetIdRef.current ? planetRefs.current[currentTargetIdRef.current] : null;

    if (!targetObj && phaseRef.current !== 'IDLE') return;

    const targetPos = new Vector3();
    if (targetObj) targetObj.getWorldPosition(targetPos);

    // Calculate distance
    const dist = currentPos.distanceTo(targetPos);

    // Update HUD Distance
    if (dist > 1000) setHudDistance(`${(dist / 100).toFixed(1)} AU`);
    else setHudDistance(`${(dist * 1000).toFixed(0)} KM`);

    // --- PHASE: ALIGNING ---
    if (phaseRef.current === 'ALIGNING') {
        setWarpCharge(0);
        shakeIntensityRef.current = 0;

        // Desired rotation: Look at target
        const dummy = new Object3D();
        dummy.position.copy(currentPos);
        dummy.lookAt(targetPos);

        // Smooth turn
        shipRef.current.quaternion.slerp(dummy.quaternion, 2.0 * delta);

        // Check alignment angle
        const forward = new Vector3(0, 0, -1).applyQuaternion(shipRef.current.quaternion);
        const dirToTarget = targetPos.clone().sub(currentPos).normalize();
        const angle = forward.angleTo(dirToTarget);

        if (angle < 0.05) {
            phaseRef.current = 'CHARGING';
            setHudMessage("正在充能曲速引擎...");
        }
    }

    // --- PHASE: CHARGING ---
    else if (phaseRef.current === 'CHARGING') {
        // Increase shake
        shakeIntensityRef.current = MathUtils.lerp(shakeIntensityRef.current, 0.1, delta);

        // Charge UI
        setWarpCharge(prev => Math.min(prev + delta * 60, 100)); // Charge in ~1.5s

        if (warpCharge >= 100) {
            phaseRef.current = 'WARPING';
            setHudMessage(">>> 跃迁启动 <<<");
        }
    }

    // --- PHASE: WARPING (Hyperdrive) ---
    else if (phaseRef.current === 'WARPING') {
        shakeIntensityRef.current = 0.2; // High shake

        // FOV Effect (Tunnel Vision)
        camera.fov = MathUtils.lerp(camera.fov, 100, delta * 5);
        camera.updateProjectionMatrix();

        // Move FAST
        const speed = dist * 2.0; // Proportional speed (Zeno's paradox style but faster)
        const dir = targetPos.clone().sub(currentPos).normalize();

        // Don't overshoot - stop at specific distance based on planet size
        const pSize = PLANETS.find(p => p.id === currentTargetIdRef.current)?.size || 5;
        const arrivalDist = pSize * 5 + 5;

        if (dist < arrivalDist + speed * delta) {
            // Arrived
            phaseRef.current = 'ARRIVING';
            setHudMessage(`抵达轨道: ${targetName}`);
        } else {
            shipRef.current.position.add(dir.multiplyScalar(speed * delta));
        }
    }

    // --- PHASE: ARRIVING (Braking) ---
    else if (phaseRef.current === 'ARRIVING') {
        shakeIntensityRef.current = MathUtils.lerp(shakeIntensityRef.current, 0, delta * 5);

        // Reset FOV
        camera.fov = MathUtils.lerp(camera.fov, 45, delta * 5);
        camera.updateProjectionMatrix();

        // Drift into orbit position
        const pSize = PLANETS.find(p => p.id === currentTargetIdRef.current)?.size || 5;
        const idealDist = pSize * 4;

        const dir = targetPos.clone().sub(currentPos).normalize();
        const stopPoint = targetPos.clone().sub(dir.multiplyScalar(idealDist));

        shipRef.current.position.lerp(stopPoint, delta * 2);

        // Look slightly up/down to frame the planet beautifully
        const viewTarget = targetPos.clone();
        shipRef.current.lookAt(viewTarget);

        if (currentPos.distanceTo(stopPoint) < 0.5) {
            phaseRef.current = 'ORBITING';
            setHudMessage(`正在扫描: ${targetName}`);

            // Stay for a few seconds then move on
            setTimeout(() => {
                nextTarget();
            }, 5000); // 5 seconds to admire
        }
    }

    // --- PHASE: ORBITING ---
    else if (phaseRef.current === 'ORBITING') {
        // Slow orbital drift
        const axis = new Vector3(0, 1, 0);
        const center = targetPos.clone();

        // Rotate position around planet
        shipRef.current.position.sub(center); // to local
        shipRef.current.position.applyAxisAngle(axis, delta * 0.1);
        shipRef.current.position.add(center); // back to world

        shipRef.current.lookAt(targetPos);
    }

  });

  return (
    <>
      {/* Ship Container - Invisible Logic Holder, but contains visible children attached to it */}
      <group ref={shipRef}>
          {/* We attach the visual elements to the ship, but the Camera also syncs to this group */}

          {/* 1. Cockpit Frame (Fixed to view) */}
          <CockpitFrame />

          {/* 2. Warp Tunnel (Visuals only visible when warping) */}
          <group rotation={[0, Math.PI, 0]}> {/* Face backwards relative to ship so particles flow towards */}
             <WarpTunnel active={phaseRef.current === 'WARPING' || phaseRef.current === 'CHARGING'} speed={1} />
          </group>

          {/* 3. Holographic HUD UI (In-World 3D UI) */}
          <group position={[0, 0, -1.2]}>
              <Html transform sprite center>
                  <div className="flex flex-col items-center justify-center w-[600px] h-[400px] font-mono select-none pointer-events-none">

                      {/* Top Bar */}
                      <div className="flex justify-between w-full px-10 mb-20 opacity-80">
                          <div className="flex flex-col text-cyan-400 text-left">
                              <span className="text-xs uppercase tracking-[0.2em] border-b border-cyan-500/50 pb-1 mb-1">TARGET SYSTEM</span>
                              <span className="text-2xl font-bold text-white drop-shadow-[0_0_5px_rgba(0,255,255,0.8)]">{targetName || "SCANNING..."}</span>
                          </div>
                          <div className="flex flex-col text-red-400 text-right">
                               <span className="text-xs uppercase tracking-[0.2em] border-b border-red-500/50 pb-1 mb-1">DISTANCE</span>
                               <span className="text-2xl font-bold text-white">{hudDistance}</span>
                          </div>
                      </div>

                      {/* Center Reticle - Dynamic */}
                      <div className={`relative flex items-center justify-center transition-all duration-500 
                          ${phaseRef.current === 'WARPING' ? 'scale-150 opacity-50' : 'scale-100 opacity-90'}`}>

                          {/* Crosshair Ring */}
                          <div className="w-24 h-24 border border-cyan-500/30 rounded-full flex items-center justify-center relative animate-[spin_10s_linear_infinite]">
                              <div className="absolute top-0 w-1 h-2 bg-cyan-400"></div>
                              <div className="absolute bottom-0 w-1 h-2 bg-cyan-400"></div>
                              <div className="absolute left-0 w-2 h-1 bg-cyan-400"></div>
                              <div className="absolute right-0 w-2 h-1 bg-cyan-400"></div>
                          </div>

                          {/* Inner Dot */}
                          <div className="absolute w-1 h-1 bg-white rounded-full shadow-[0_0_10px_white]"></div>

                          {/* Charging Ring */}
                          {phaseRef.current === 'CHARGING' && (
                              <svg className="absolute w-32 h-32 -rotate-90">
                                  <circle cx="64" cy="64" r="60" stroke="#1e293b" strokeWidth="4" fill="none" />
                                  <circle cx="64" cy="64" r="60" stroke="#facc15" strokeWidth="4" fill="none" 
                                          strokeDasharray="377" strokeDashoffset={377 - (377 * warpCharge) / 100} 
                                          className="transition-all duration-100 ease-linear" />
                              </svg>
                          )}
                      </div>

                      {/* Bottom Status Message */}
                      <div className="mt-20 bg-black/60 backdrop-blur-md border-x-2 border-cyan-500 px-6 py-2">
                          <span className={`text-lg font-bold tracking-wider ${phaseRef.current === 'WARPING' ? 'text-yellow-400 animate-pulse' : 'text-cyan-200'}`}>
                             {hudMessage}
                          </span>
                      </div>

                  </div>
              </Html>
          </group>
      </group>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  isGestureMode: boolean;
  toggleGestureMode: () => void;
  showOrbits: boolean;
  toggleOrbits: () => void;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
  simulationSpeed,
  setSimulationSpeed,
  isStarshipActive,
  toggleStarship,
  showPluto,
  togglePluto,
  toggleGestureMode,
  isGestureMode,
  showOrbits,
  toggleOrbits
}) => {
  // TTS State
  const [isSpeaking, setIsSpeaking] = useState(false);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  // 1. Initialize Voices
  useEffect(() => {
    const loadVoices = () => {
        const voices = synthRef.current.getVoices();
        setAvailableVoices(voices);
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
        window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  // Stop speech when planet changes or panel closes
  useEffect(() => {
    const stopSpeaking = () => {
      if (synthRef.current.speaking) {
        synthRef.current.cancel();
        setIsSpeaking(false);
      }
    };
    stopSpeaking(); 
    return () => { stopSpeaking(); };
  }, [selectedPlanet]);

  // Helper: Find voice
  const getBestVoice = () => {
      const zhVoices = availableVoices.filter(v => v.lang.includes('zh') || v.lang.includes('CN'));
      const xiaoxiao = zhVoices.find(v => v.name.includes('Xiaoxiao') || v.name.includes('Natural'));
      if (xiaoxiao) return xiaoxiao;
      const google = zhVoices.find(v => v.name.includes('Google'));
      if (google) return google;
      return zhVoices[0] || null;
  };

  const toggleSpeech = () => {
    if (!selectedPlanet) return;
    if (isSpeaking) {
      synthRef.current.cancel();
      setIsSpeaking(false);
    } else {
      const planetName = selectedPlanet.name.split(' ')[0];
      const intro = `嗨！小朋友，你好呀！欢迎来到${planetName}。我是你们的导游。`;
      const desc = selectedPlanet.description; 
      const funFact = selectedPlanet.funFact ? `哇，还有一个神奇的小秘密要告诉你：${selectedPlanet.funFact}` : '';
      const outro = "怎么样？宇宙是不是超级有趣呢？";
      const fullText = `${intro} ${desc} ${funFact} ${outro}`;
      const utterance = new SpeechSynthesisUtterance(fullText);
      utterance.lang = 'zh-CN';
      const bestVoice = getBestVoice();
      if (bestVoice) utterance.voice = bestVoice;
      utterance.rate = 0.9; 
      utterance.pitch = 1.1; 
      utterance.volume = 1.0;
      utterance.onend = () => setIsSpeaking(false);
      utterance.onerror = () => setIsSpeaking(false);
      synthRef.current.speak(utterance);
      setIsSpeaking(true);
    }
  };

  const calculateTravelTime = (planet: PlanetData) => {
    const distanceKm = planet.realDistance * 1000000;
    const lightMinutes = (planet.realDistance / 18).toFixed(1);
    const planeHours = distanceKm / 900;
    const planeYears = (planeHours / 24 / 365).toFixed(1);
    const rocketHours = distanceKm / 40000;
    const rocketDays = Math.round(rocketHours / 24);
    const rocketYears = (rocketHours / 24 / 365).toFixed(1);
    const rocketTimeDisplay = rocketDays > 365 ? `${rocketYears} 年` : `${rocketDays} 天`;
    return { lightMinutes, planeYears, rocketTimeDisplay };
  };

  const travelInfo = selectedPlanet ? calculateTravelTime(selectedPlanet) : null;
  const MOON_IDS = ['io', 'europa', 'ganymede', 'callisto', 'moon', 'titan', 'enceladus', 'mimas', 'iapetus'];
  const isMoon = selectedPlanet && MOON_IDS.includes(selectedPlanet.id);
  const showTravelTime = selectedPlanet && selectedPlanet.id !== 'earth' && selectedPlanet.id !== 'sun' && !isMoon;
  const isEarth = selectedPlanet?.id === 'earth';

  const getPlanetTheme = (planet: PlanetData) => {
    if (planet.id === 'sun') return { icon: '☀️', type: '恒星' };
    if (planet.id === 'earth') return { icon: '🌍', type: '生命家园' };
    if (planet.id === 'pluto') return { icon: '❄️', type: '矮行星' };
    if (planet.id === 'tiangong') return { icon: '🛰️', type: '空间站' };
    if (MOON_IDS.includes(planet.id)) return { icon: '🌑', type: '卫星' };
    if (planet.realDistance < 200) return { icon: '🪨', type: '岩石系' }; 
    if (planet.hasRings) return { icon: '🪐', type: '飞行系' };
    if (planet.realDistance > 2000) return { icon: '🧊', type: '冰系' };
    return { icon: '🎈', type: '气体系' };
  };

  const getDistanceFromEarth = (planet: PlanetData) => {
    if (planet.id === 'earth') return '0';
