import React, { useRef, useState, useEffect, useMemo } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import { Vector3, Group, Object3D, MathUtils, Euler, Quaternion, Matrix4, AdditiveBlending } from 'three';
import { Html, Text } from '@react-three/drei';
import { PLANETS, SUN_DATA } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

type FlightPhase = 'IDLE' | 'ALIGNING' | 'CHARGING' | 'WARPING' | 'ARRIVING' | 'ORBITING';

// --- WARP TUNNEL EFFECT ---
// Creates the "Star Wars" hyperspace streak effect
const WarpTunnel = ({ active, speed }: { active: boolean, speed: number }) => {
    const count = 400;
    const meshRef = useRef<any>(null);
    const dummy = useMemo(() => new Object3D(), []);

    // Random initial positions for stars
    const particles = useMemo(() => {
        return new Array(count).fill(0).map(() => ({
            x: MathUtils.randFloatSpread(100),
            y: MathUtils.randFloatSpread(100),
            z: MathUtils.randFloat(-50, -500), // Start far ahead
            speed: MathUtils.randFloat(1, 5)
        }));
    }, []);

    useFrame((state, delta) => {
        if (!meshRef.current) return;

        // If not warping, hide or slow down significantly
        const warpFactor = active ? 200 : 2; 

        particles.forEach((p, i) => {
            // Move particles towards camera (Z-positive)
            p.z += p.speed * warpFactor * delta;

            // Reset if passed camera
            if (p.z > 10) {
                p.z = -500;
                p.x = MathUtils.randFloatSpread(100);
                p.y = MathUtils.randFloatSpread(100);
            }

            dummy.position.set(p.x, p.y, p.z);
            // Stretch based on speed
            const scaleZ = active ? MathUtils.randFloat(10, 50) : 1;
            dummy.scale.set(0.1, 0.1, scaleZ); 
            dummy.updateMatrix();
            meshRef.current.setMatrixAt(i, dummy.matrix);
        });
        meshRef.current.instanceMatrix.needsUpdate = true;
    });

    return (
        <instancedMesh ref={meshRef} args={[undefined, undefined, count]} frustumCulled={false}>
            <boxGeometry args={[1, 1, 1]} />
            <meshBasicMaterial 
                color="#00FFFF" 
                transparent 
                opacity={active ? 0.6 : 0} 
                blending={AdditiveBlending} 
            />
        </instancedMesh>
    );
};

// --- COCKPIT FRAME ---
// A simple frame to give depth and the feeling of being inside a helmet/ship
const CockpitFrame = () => {
    return (
        <group position={[0, 0, -1]}> 
            {/* Top Bar */}
