             {/* Left Pillar */}
             <mesh position={[-1.2, 0, 0]} rotation={[0, 0, -0.1]}>
                <boxGeometry args={[0.2, 1.2, 0.2]} />
                <meshStandardMaterial color="#111" roughness={0.2} metalness={0.8} />
            </mesh>
            {/* Right Pillar */}
            <mesh position={[1.2, 0, 0]} rotation={[0, 0, 0.1]}>
