export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const { camera } = useThree();
  const shipRef = useRef<Group>(null);

  // State
  const [hudMessage, setHudMessage] = useState("系统初始化...");
  const [hudDistance, setHudDistance] = useState("---");
  const [targetName, setTargetName] = useState("");
  const [warpCharge, setWarpCharge] = useState(0); // 0 to 100

  // Logic Refs
  const phaseRef = useRef<FlightPhase>('IDLE');
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);
  const velocityRef = useRef(new Vector3(0, 0, 0));
  const lookAtTargetRef = useRef(new Vector3());

  // Shake effect
  const shakeIntensityRef = useRef(0);

  // Initialize Mission
  useEffect(() => {
    // A curated "Grand Tour"
    const tour = ['mercury', 'venus', 'earth', 'mars', 'jupiter', 'saturn', 'uranus', 'neptune'];
    // Filter out start position if we are already there (usually starts at Earth or Sun, let's start fresh)
    missionQueueRef.current = tour;

    // Spawn ship near Sun initially for the "Grand Tour" start, or Earth?
    // Let's spawn near Earth for familiarity, then go to Mercury.
    if (planetRefs.current['sun'] && shipRef.current) {
        // Start high above the ecliptic for a view
        shipRef.current.position.set(0, 40, 60); 
        shipRef.current.lookAt(0, 0, 0);
    }

    // Start delay
    setTimeout(() => {
        nextTarget();
    }, 2000);
  }, []);

  const nextTarget = () => {
      if (missionQueueRef.current.length === 0) {
          setHudMessage("旅程结束 - 返回基地");
          onMissionComplete();
          return;
      }

      const nextId = missionQueueRef.current.shift()!;
      currentTargetIdRef.current = nextId;
      const p = PLANETS.find(x => x.id === nextId);
      setTargetName(p?.name || nextId);

      setHudMessage(`锁定目标: ${p?.name}`);
      phaseRef.current = 'ALIGNING';
  };

  useFrame((state, delta) => {
    if (!shipRef.current) return;

    // 1. FPV Camera Sync
    // The camera IS the pilot's eyes. It follows the ship group exactly.
    // We add a tiny bit of "head bob" or shake based on phase.
    const shakeX = (Math.random() - 0.5) * shakeIntensityRef.current;
    const shakeY = (Math.random() - 0.5) * shakeIntensityRef.current;
    const shakeZ = (Math.random() - 0.5) * shakeIntensityRef.current;

    camera.position.copy(shipRef.current.position).add(new Vector3(shakeX, shakeY, shakeZ));
    camera.quaternion.copy(shipRef.current.quaternion);

    // 2. Logic Machine
    const currentPos = shipRef.current.position.clone();
    let targetObj = currentTargetIdRef.current ? planetRefs.current[currentTargetIdRef.current] : null;

    if (!targetObj && phaseRef.current !== 'IDLE') return;

    const targetPos = new Vector3();
    if (targetObj) targetObj.getWorldPosition(targetPos);

    // Calculate distance
    const dist = currentPos.distanceTo(targetPos);

    // Update HUD Distance
    if (dist > 1000) setHudDistance(`${(dist / 100).toFixed(1)} AU`);
    else setHudDistance(`${(dist * 1000).toFixed(0)} KM`);

    // --- PHASE: ALIGNING ---
    if (phaseRef.current === 'ALIGNING') {
        setWarpCharge(0);
        shakeIntensityRef.current = 0;

        // Desired rotation: Look at target
        const dummy = new Object3D();
        dummy.position.copy(currentPos);
        dummy.lookAt(targetPos);

        // Smooth turn
        shipRef.current.quaternion.slerp(dummy.quaternion, 2.0 * delta);

        // Check alignment angle
        const forward = new Vector3(0, 0, -1).applyQuaternion(shipRef.current.quaternion);
        const dirToTarget = targetPos.clone().sub(currentPos).normalize();
        const angle = forward.angleTo(dirToTarget);

        if (angle < 0.05) {
            phaseRef.current = 'CHARGING';
            setHudMessage("正在充能曲速引擎...");
        }
    }

    // --- PHASE: CHARGING ---
    else if (phaseRef.current === 'CHARGING') {
        // Increase shake
        shakeIntensityRef.current = MathUtils.lerp(shakeIntensityRef.current, 0.1, delta);

        // Charge UI
        setWarpCharge(prev => Math.min(prev + delta * 60, 100)); // Charge in ~1.5s

        if (warpCharge >= 100) {
            phaseRef.current = 'WARPING';
            setHudMessage(">>> 跃迁启动 <<<");
        }
    }

    // --- PHASE: WARPING (Hyperdrive) ---
    else if (phaseRef.current === 'WARPING') {
        shakeIntensityRef.current = 0.2; // High shake

        // FOV Effect (Tunnel Vision)
        camera.fov = MathUtils.lerp(camera.fov, 100, delta * 5);
        camera.updateProjectionMatrix();

        // Move FAST
        const speed = dist * 2.0; // Proportional speed (Zeno's paradox style but faster)
        const dir = targetPos.clone().sub(currentPos).normalize();

        // Don't overshoot - stop at specific distance based on planet size
        const pSize = PLANETS.find(p => p.id === currentTargetIdRef.current)?.size || 5;
        const arrivalDist = pSize * 5 + 5;

        if (dist < arrivalDist + speed * delta) {
            // Arrived
            phaseRef.current = 'ARRIVING';
            setHudMessage(`抵达轨道: ${targetName}`);
        } else {
            shipRef.current.position.add(dir.multiplyScalar(speed * delta));
        }
    }

    // --- PHASE: ARRIVING (Braking) ---
    else if (phaseRef.current === 'ARRIVING') {
        shakeIntensityRef.current = MathUtils.lerp(shakeIntensityRef.current, 0, delta * 5);

        // Reset FOV
        camera.fov = MathUtils.lerp(camera.fov, 45, delta * 5);
        camera.updateProjectionMatrix();

        // Drift into orbit position
        const pSize = PLANETS.find(p => p.id === currentTargetIdRef.current)?.size || 5;
        const idealDist = pSize * 4;

        const dir = targetPos.clone().sub(currentPos).normalize();
        const stopPoint = targetPos.clone().sub(dir.multiplyScalar(idealDist));

        shipRef.current.position.lerp(stopPoint, delta * 2);

        // Look slightly up/down to frame the planet beautifully
        const viewTarget = targetPos.clone();
        shipRef.current.lookAt(viewTarget);

        if (currentPos.distanceTo(stopPoint) < 0.5) {
            phaseRef.current = 'ORBITING';
            setHudMessage(`正在扫描: ${targetName}`);

            // Stay for a few seconds then move on
            setTimeout(() => {
                nextTarget();
            }, 5000); // 5 seconds to admire
        }
    }

    // --- PHASE: ORBITING ---
    else if (phaseRef.current === 'ORBITING') {
        // Slow orbital drift
        const axis = new Vector3(0, 1, 0);
        const center = targetPos.clone();

        // Rotate position around planet
        shipRef.current.position.sub(center); // to local
        shipRef.current.position.applyAxisAngle(axis, delta * 0.1);
        shipRef.current.position.add(center); // back to world

        shipRef.current.lookAt(targetPos);
    }

  });

  return (
    <>
      {/* Ship Container - Invisible Logic Holder, but contains visible children attached to it */}
      <group ref={shipRef}>
          {/* We attach the visual elements to the ship, but the Camera also syncs to this group */}

          {/* 1. Cockpit Frame (Fixed to view) */}
          <CockpitFrame />

          {/* 2. Warp Tunnel (Visuals only visible when warping) */}
          <group rotation={[0, Math.PI, 0]}> {/* Face backwards relative to ship so particles flow towards */}
             <WarpTunnel active={phaseRef.current === 'WARPING' || phaseRef.current === 'CHARGING'} speed={1} />
          </group>

          {/* 3. Holographic HUD UI (In-World 3D UI) */}
          <group position={[0, 0, -1.2]}>
              <Html transform sprite center>
                  <div className="flex flex-col items-center justify-center w-[600px] h-[400px] font-mono select-none pointer-events-none">

                      {/* Top Bar */}
                      <div className="flex justify-between w-full px-10 mb-20 opacity-80">
