                              <span className="text-2xl font-bold text-white drop-shadow-[0_0_5px_rgba(0,255,255,0.8)]">{targetName || "SCANNING..."}</span>
                          </div>
                          <div className="flex flex-col text-red-400 text-right">
                               <span className="text-xs uppercase tracking-[0.2em] border-b border-red-500/50 pb-1 mb-1">DISTANCE</span>
                               <span className="text-2xl font-bold text-white">{hudDistance}</span>
                          </div>
                      </div>

                      {/* Center Reticle - Dynamic */}
                      <div className={`relative flex items-center justify-center transition-all duration-500 
                          ${phaseRef.current === 'WARPING' ? 'scale-150 opacity-50' : 'scale-100 opacity-90'}`}>

                          {/* Crosshair Ring */}
                          <div className="w-24 h-24 border border-cyan-500/30 rounded-full flex items-center justify-center relative animate-[spin_10s_linear_infinite]">
                              <div className="absolute top-0 w-1 h-2 bg-cyan-400"></div>
                              <div className="absolute bottom-0 w-1 h-2 bg-cyan-400"></div>
                              <div className="absolute left-0 w-2 h-1 bg-cyan-400"></div>
                              <div className="absolute right-0 w-2 h-1 bg-cyan-400"></div>
                          </div>

                          {/* Inner Dot */}
                          <div className="absolute w-1 h-1 bg-white rounded-full shadow-[0_0_10px_white]"></div>

                          {/* Charging Ring */}
                          {phaseRef.current === 'CHARGING' && (
                              <svg className="absolute w-32 h-32 -rotate-90">
                                  <circle cx="64" cy="64" r="60" stroke="#1e293b" strokeWidth="4" fill="none" />
                                  <circle cx="64" cy="64" r="60" stroke="#facc15" strokeWidth="4" fill="none" 
                                          strokeDasharray="377" strokeDashoffset={377 - (377 * warpCharge) / 100} 
                                          className="transition-all duration-100 ease-linear" />
                              </svg>
                          )}
                      </div>

                      {/* Bottom Status Message */}
                      <div className="mt-20 bg-black/60 backdrop-blur-md border-x-2 border-cyan-500 px-6 py-2">
                          <span className={`text-lg font-bold tracking-wider ${phaseRef.current === 'WARPING' ? 'text-yellow-400 animate-pulse' : 'text-cyan-200'}`}>
                             {hudMessage}
                          </span>
                      </div>

                  </div>
              </Html>
          </group>
      </group>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  isGestureMode: boolean;
  toggleGestureMode: () => void;
  showOrbits: boolean;
  toggleOrbits: () => void;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
  simulationSpeed,
  setSimulationSpeed,
  isStarshipActive,
  toggleStarship,
  showPluto,
  togglePluto,
  toggleGestureMode,
  isGestureMode,
  showOrbits,
  toggleOrbits
}) => {
  // TTS State
  const [isSpeaking, setIsSpeaking] = useState(false);
  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  // 1. Initialize Voices
  useEffect(() => {
    const loadVoices = () => {
        const voices = synthRef.current.getVoices();
        setAvailableVoices(voices);
    };
    loadVoices();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
        window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  // Stop speech when planet changes or panel closes
  useEffect(() => {
    const stopSpeaking = () => {
      if (synthRef.current.speaking) {
        synthRef.current.cancel();
        setIsSpeaking(false);
      }
    };
    stopSpeaking(); 
    return () => { stopSpeaking(); };
  }, [selectedPlanet]);

  // Helper: Find voice
  const getBestVoice = () => {
      const zhVoices = availableVoices.filter(v => v.lang.includes('zh') || v.lang.includes('CN'));
      const xiaoxiao = zhVoices.find(v => v.name.includes('Xiaoxiao') || v.name.includes('Natural'));
      if (xiaoxiao) return xiaoxiao;
      const google = zhVoices.find(v => v.name.includes('Google'));
      if (google) return google;
      return zhVoices[0] || null;
  };

  const toggleSpeech = () => {
    if (!selectedPlanet) return;
    if (isSpeaking) {
      synthRef.current.cancel();
      setIsSpeaking(false);
    } else {
      const planetName = selectedPlanet.name.split(' ')[0];
      const intro = `嗨！小朋友，你好呀！欢迎来到${planetName}。我是你们的导游。`;
      const desc = selectedPlanet.description; 
      const funFact = selectedPlanet.funFact ? `哇，还有一个神奇的小秘密要告诉你：${selectedPlanet.funFact}` : '';
      const outro = "怎么样？宇宙是不是超级有趣呢？";
      const fullText = `${intro} ${desc} ${funFact} ${outro}`;
      const utterance = new SpeechSynthesisUtterance(fullText);
      utterance.lang = 'zh-CN';
      const bestVoice = getBestVoice();
      if (bestVoice) utterance.voice = bestVoice;
      utterance.rate = 0.9; 
      utterance.pitch = 1.1; 
      utterance.volume = 1.0;
      utterance.onend = () => setIsSpeaking(false);
      utterance.onerror = () => setIsSpeaking(false);
      synthRef.current.speak(utterance);
      setIsSpeaking(true);
    }
  };

  const calculateTravelTime = (planet: PlanetData) => {
    const distanceKm = planet.realDistance * 1000000;
    const lightMinutes = (planet.realDistance / 18).toFixed(1);
    const planeHours = distanceKm / 900;
    const planeYears = (planeHours / 24 / 365).toFixed(1);
    const rocketHours = distanceKm / 40000;
    const rocketDays = Math.round(rocketHours / 24);
    const rocketYears = (rocketHours / 24 / 365).toFixed(1);
    const rocketTimeDisplay = rocketDays > 365 ? `${rocketYears} 年` : `${rocketDays} 天`;
    return { lightMinutes, planeYears, rocketTimeDisplay };
  };

  const travelInfo = selectedPlanet ? calculateTravelTime(selectedPlanet) : null;
  const MOON_IDS = ['io', 'europa', 'ganymede', 'callisto', 'moon', 'titan', 'enceladus', 'mimas', 'iapetus'];
  const isMoon = selectedPlanet && MOON_IDS.includes(selectedPlanet.id);
  const showTravelTime = selectedPlanet && selectedPlanet.id !== 'earth' && selectedPlanet.id !== 'sun' && !isMoon;
  const isEarth = selectedPlanet?.id === 'earth';

  const getPlanetTheme = (planet: PlanetData) => {
    if (planet.id === 'sun') return { icon: '☀️', type: '恒星' };
